INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Hebrews', 3, 9, 'where your fathers tested me and tried me, and saw my deeds for forty years.'),
  ('Hebrews', 3, 10, 'Therefore I was displeased with that generation, and said, ‘They always err in their heart, but they didn’t know my ways.’'),
  ('Hebrews', 3, 11, 'As I swore in my wrath, ‘They will not enter into my rest.’”'),
  ('Hebrews', 3, 12, 'Beware, brothers, lest perhaps there might be in any one of you an evil heart of unbelief, in falling away from the living God;'),
  ('Hebrews', 3, 13, 'but exhort one another day by day, so long as it is called “today”, lest any one of you be hardened by the deceitfulness of sin.'),
  ('Hebrews', 3, 14, 'For we have become partakers of Christ, if we hold the beginning of our confidence firm to the end,'),
  ('Hebrews', 3, 15, 'while it is said, “Today if you will hear his voice, don’t harden your hearts, as in the rebellion.”'),
  ('Hebrews', 3, 16, 'For who, when they heard, rebelled? Wasn’t it all those who came out of Egypt led by Moses?'),
  ('Hebrews', 3, 17, 'With whom was he displeased forty years? Wasn’t it with those who sinned, whose bodies fell in the wilderness?'),
  ('Hebrews', 3, 18, 'To whom did he swear that they wouldn’t enter into his rest, but to those who were disobedient?'),
  ('Hebrews', 3, 19, 'We see that they weren’t able to enter in because of unbelief.'),
  ('Hebrews', 4, 1, 'Let’s fear therefore, lest perhaps anyone of you should seem to have come short of a promise of entering into his rest.'),
  ('Hebrews', 4, 2, 'For indeed we have had good news preached to us, even as they also did, but the word they heard didn’t profit them, because it wasn’t mixed with faith by those who heard.'),
  ('Hebrews', 4, 3, 'For we who have believed do enter into that rest, even as he has said, “As I swore in my wrath, they will not enter into my rest;” although the works were finished from the foundation of the world.'),
  ('Hebrews', 4, 4, 'For he has said this somewhere about the seventh day, “God rested on the seventh day from all his works;”'),
  ('Hebrews', 4, 5, 'and in this place again, “They will not enter into my rest.”'),
  ('Hebrews', 4, 6, 'Seeing therefore it remains that some should enter into it, and they to whom the good news was preached before failed to enter in because of disobedience,'),
  ('Hebrews', 4, 7, 'he again defines a certain day, “today”, saying through David so long a time afterward (just as has been said), “Today if you will hear his voice, don’t harden your hearts.”'),
  ('Hebrews', 4, 8, 'For if Joshua had given them rest, he would not have spoken afterward of another day.'),
  ('Hebrews', 4, 9, 'There remains therefore a Sabbath rest for the people of God.'),
  ('Hebrews', 4, 10, 'For he who has entered into his rest has himself also rested from his works, as God did from his.'),
  ('Hebrews', 4, 11, 'Let’s therefore give diligence to enter into that rest, lest anyone fall after the same example of disobedience.'),
  ('Hebrews', 4, 12, 'For the word of God is living and active, and sharper than any two-edged sword, piercing even to the dividing of soul and spirit, of both joints and marrow, and is able to discern the thoughts and intentions of the heart.'),
  ('Hebrews', 4, 13, 'There is no creature that is hidden from his sight, but all things are naked and laid open before the eyes of him to whom we must give an account.'),
  ('Hebrews', 4, 14, 'Having then a great high priest who has passed through the heavens, Jesus, the Son of God, let’s hold tightly to our confession.'),
  ('Hebrews', 4, 15, 'For we don’t have a high priest who can’t be touched with the feeling of our infirmities, but one who has been in all points tempted like we are, yet without sin.'),
  ('Hebrews', 4, 16, 'Let’s therefore draw near with boldness to the throne of grace, that we may receive mercy and may find grace for help in time of need.'),
  ('Hebrews', 5, 1, 'For every high priest, being taken from among men, is appointed for men in things pertaining to God, that he may offer both gifts and sacrifices for sins.'),
  ('Hebrews', 5, 2, 'The high priest can deal gently with those who are ignorant and going astray, because he himself is also surrounded with weakness.'),
  ('Hebrews', 5, 3, 'Because of this, he must offer sacrifices for sins for the people, as well as for himself.'),
  ('Hebrews', 5, 4, 'Nobody takes this honor on himself, but he is called by God, just like Aaron was.'),
  ('Hebrews', 5, 5, 'So also Christ didn’t glorify himself to be made a high priest, but it was he who said to him, “You are my Son. Today I have become your father.”'),
  ('Hebrews', 5, 6, 'As he says also in another place, “You are a priest forever, after the order of Melchizedek.”'),
  ('Hebrews', 5, 7, 'He, in the days of his flesh, having offered up prayers and petitions with strong crying and tears to him who was able to save him from death, and having been heard for his godly fear,'),
  ('Hebrews', 5, 8, 'though he was a Son, yet learned obedience by the things which he suffered.'),
  ('Hebrews', 5, 9, 'Having been made perfect, he became to all of those who obey him the author of eternal salvation,'),
  ('Hebrews', 5, 10, 'named by God a high priest after the order of Melchizedek.'),
  ('Hebrews', 5, 11, 'About him we have many words to say, and hard to interpret, seeing you have become dull of hearing.'),
  ('Hebrews', 5, 12, 'For although by this time you should be teachers, you again need to have someone teach you the rudiments of the first principles of the revelations of God. You have come to need milk, and not solid food.'),
  ('Hebrews', 5, 13, 'For everyone who lives on milk is not experienced in the word of righteousness, for he is a baby.'),
  ('Hebrews', 5, 14, 'But solid food is for those who are full grown, who by reason of use have their senses exercised to discern good and evil.'),
  ('Hebrews', 6, 1, 'Therefore leaving the teaching of the first principles of Christ, let’s press on to perfection—not laying again a foundation of repentance from dead works, of faith toward God,'),
  ('Hebrews', 6, 2, 'of the teaching of baptisms, of laying on of hands, of resurrection of the dead, and of eternal judgment.'),
  ('Hebrews', 6, 3, 'This will we do, if God permits.'),
  ('Hebrews', 6, 4, 'For concerning those who were once enlightened and tasted of the heavenly gift, and were made partakers of the Holy Spirit,'),
  ('Hebrews', 6, 5, 'and tasted the good word of God and the powers of the age to come,'),
  ('Hebrews', 6, 6, 'and then fell away, it is impossible to renew them again to repentance; seeing they crucify the Son of God for themselves again, and put him to open shame.'),
  ('Hebrews', 6, 7, 'For the land which has drunk the rain that comes often on it and produces a crop suitable for them for whose sake it is also tilled, receives blessing from God;'),
  ('Hebrews', 6, 8, 'but if it bears thorns and thistles, it is rejected and near being cursed, whose end is to be burned.'),
  ('Hebrews', 6, 9, 'But, beloved, we are persuaded of better things for you, and things that accompany salvation, even though we speak like this.'),
  ('Hebrews', 6, 10, 'For God is not unrighteous, so as to forget your work and the labor of love which you showed toward his name, in that you served the saints, and still do serve them.'),
  ('Hebrews', 6, 11, 'We desire that each one of you may show the same diligence to the fullness of hope even to the end,'),
  ('Hebrews', 6, 12, 'that you won’t be sluggish, but imitators of those who through faith and perseverance inherited the promises.'),
  ('Hebrews', 6, 13, 'For when God made a promise to Abraham, since he could swear by no one greater, he swore by himself,'),
  ('Hebrews', 6, 14, 'saying, “Surely blessing I will bless you, and multiplying I will multiply you.”'),
  ('Hebrews', 6, 15, 'Thus, having patiently endured, he obtained the promise.'),
  ('Hebrews', 6, 16, 'For men indeed swear by a greater one, and in every dispute of theirs the oath is final for confirmation.'),
  ('Hebrews', 6, 17, 'In this way God, being determined to show more abundantly to the heirs of the promise the immutability of his counsel, interposed with an oath,'),
  ('Hebrews', 6, 18, 'that by two immutable things, in which it is impossible for God to lie, we may have a strong encouragement, who have fled for refuge to take hold of the hope set before us.'),
  ('Hebrews', 6, 19, 'This hope we have as an anchor of the soul, a hope both sure and steadfast and entering into that which is within the veil,'),
  ('Hebrews', 6, 20, 'where as a forerunner Jesus entered for us, having become a high priest forever after the order of Melchizedek.'),
  ('Hebrews', 7, 1, 'For this Melchizedek, king of Salem, priest of God Most High, who met Abraham returning from the slaughter of the kings and blessed him,'),
  ('Hebrews', 7, 2, 'to whom also Abraham divided a tenth part of all (being first, by interpretation, “king of righteousness”, and then also “king of Salem”, which means “king of peace”,'),
  ('Hebrews', 7, 3, 'without father, without mother, without genealogy, having neither beginning of days nor end of life, but made like the Son of God), remains a priest continually.'),
  ('Hebrews', 7, 4, 'Now consider how great this man was, to whom even Abraham the patriarch gave a tenth out of the best plunder.'),
  ('Hebrews', 7, 5, 'They indeed of the sons of Levi who receive the priest’s office have a commandment to take tithes from the people according to the law, that is, of their brothers, though these have come out of the body of Abraham,'),
  ('Hebrews', 7, 6, 'but he whose genealogy is not counted from them has accepted tithes from Abraham, and has blessed him who has the promises.'),
  ('Hebrews', 7, 7, 'But without any dispute the lesser is blessed by the greater.'),
  ('Hebrews', 7, 8, 'Here people who die receive tithes, but there one receives tithes of whom it is testified that he lives.'),
  ('Hebrews', 7, 9, 'We can say that through Abraham even Levi, who receives tithes, has paid tithes,'),
  ('Hebrews', 7, 10, 'for he was yet in the body of his father when Melchizedek met him.'),
  ('Hebrews', 7, 11, 'Now if perfection was through the Levitical priesthood (for under it the people have received the law), what further need was there for another priest to arise after the order of Melchizedek, and not be called after the order of Aaron?'),
  ('Hebrews', 7, 12, 'For the priesthood being changed, there is of necessity a change made also in the law.'),
  ('Hebrews', 7, 13, 'For he of whom these things are said belongs to another tribe, from which no one has officiated at the altar.'),
  ('Hebrews', 7, 14, 'For it is evident that our Lord has sprung out of Judah, about which tribe Moses spoke nothing concerning priesthood.'),
  ('Hebrews', 7, 15, 'This is yet more abundantly evident, if after the likeness of Melchizedek there arises another priest,'),
  ('Hebrews', 7, 16, 'who has been made, not after the law of a fleshly commandment, but after the power of an endless life;'),
  ('Hebrews', 7, 17, 'for it is testified, “You are a priest forever, according to the order of Melchizedek.”'),
  ('Hebrews', 7, 18, 'For there is an annulling of a foregoing commandment because of its weakness and uselessness'),
  ('Hebrews', 7, 19, '(for the law made nothing perfect), and a bringing in of a better hope, through which we draw near to God.'),
  ('Hebrews', 7, 20, 'Inasmuch as he was not made priest without the taking of an oath'),
  ('Hebrews', 7, 21, '(for they indeed have been made priests without an oath), but he with an oath by him that says of him, “The Lord swore and will not change his mind, ‘You are a priest forever, according to the order of Melchizedek.’”'),
  ('Hebrews', 7, 22, 'By so much, Jesus has become the guarantee of a better covenant.'),
  ('Hebrews', 7, 23, 'Many, indeed, have been made priests, because they are hindered from continuing by death.'),
  ('Hebrews', 7, 24, 'But he, because he lives forever, has his priesthood unchangeable.'),
  ('Hebrews', 7, 25, 'Therefore he is also able to save to the uttermost those who draw near to God through him, seeing that he lives forever to make intercession for them.'),
  ('Hebrews', 7, 26, 'For such a high priest was fitting for us: holy, guiltless, undefiled, separated from sinners, and made higher than the heavens;'),
  ('Hebrews', 7, 27, 'who doesn’t need, like those high priests, to offer up sacrifices daily, first for his own sins, and then for the sins of the people. For he did this once for all, when he offered up himself.'),
  ('Hebrews', 7, 28, 'For the law appoints men as high priests who have weakness, but the word of the oath, which came after the law, appoints a Son forever who has been perfected.'),
  ('Hebrews', 8, 1, 'Now in the things which we are saying, the main point is this: we have such a high priest, who sat down on the right hand of the throne of the Majesty in the heavens,'),
  ('Hebrews', 8, 2, 'a servant of the sanctuary and of the true tabernacle which the Lord pitched, not man.'),
  ('Hebrews', 8, 3, 'For every high priest is appointed to offer both gifts and sacrifices. Therefore it is necessary that this high priest also have something to offer.'),
  ('Hebrews', 8, 4, 'For if he were on earth, he would not be a priest at all, seeing there are priests who offer the gifts according to the law,'),
  ('Hebrews', 8, 5, 'who serve a copy and shadow of the heavenly things, even as Moses was warned by God when he was about to make the tabernacle, for he said, “See, you shall make everything according to the pattern that was shown to you on the mountain.”'),
  ('Hebrews', 8, 6, 'But now he has obtained a more excellent ministry, by as much as he is also the mediator of a better covenant, which on better promises has been given as law.'),
  ('Hebrews', 8, 7, 'For if that first covenant had been faultless, then no place would have been sought for a second.'),
  ('Hebrews', 8, 8, 'For finding fault with them, he said, “Behold, the days are coming”, says the Lord, “that I will make a new covenant with the house of Israel and with the house of Judah;'),
  ('Hebrews', 8, 9, 'not according to the covenant that I made with their fathers in the day that I took them by the hand to lead them out of the land of Egypt; for they didn’t continue in my covenant, and I disregarded them,” says the Lord.'),
  ('Hebrews', 8, 10, '“For this is the covenant that I will make with the house of Israel after those days,” says the Lord: “I will put my laws into their mind; I will also write them on their heart. I will be their God, and they will be my people.'),
  ('Hebrews', 8, 11, 'They will not teach every man his fellow citizen and every man his brother, saying, ‘Know the Lord,’ for all will know me, from their least to their greatest.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Hebrews', 8, 12, 'For I will be merciful to their unrighteousness. I will remember their sins and lawless deeds no more.”'),
  ('Hebrews', 8, 13, 'In that he says, “A new covenant”, he has made the first obsolete. But that which is becoming obsolete and grows aged is near to vanishing away.'),
  ('Hebrews', 9, 1, 'Now indeed even the first covenant had ordinances of divine service and an earthly sanctuary.'),
  ('Hebrews', 9, 2, 'For a tabernacle was prepared. In the first part were the lamp stand, the table, and the show bread, which is called the Holy Place.'),
  ('Hebrews', 9, 3, 'After the second veil was the tabernacle which is called the Holy of Holies,'),
  ('Hebrews', 9, 4, 'having a golden altar of incense and the ark of the covenant overlaid on all sides with gold, in which was a golden pot holding the manna, Aaron’s rod that budded, and the tablets of the covenant;'),
  ('Hebrews', 9, 5, 'and above it cherubim of glory overshadowing the mercy seat, of which things we can’t speak now in detail.'),
  ('Hebrews', 9, 6, 'Now these things having been thus prepared, the priests go in continually into the first tabernacle, accomplishing the services,'),
  ('Hebrews', 9, 7, 'but into the second the high priest alone, once in the year, not without blood, which he offers for himself and for the errors of the people.'),
  ('Hebrews', 9, 8, 'The Holy Spirit is indicating this, that the way into the Holy Place wasn’t yet revealed while the first tabernacle was still standing.'),
  ('Hebrews', 9, 9, 'This is a symbol of the present age, where gifts and sacrifices are offered that are incapable, concerning the conscience, of making the worshiper perfect,'),
  ('Hebrews', 9, 10, 'being only (with foods and drinks and various washings) fleshly ordinances, imposed until a time of reformation.'),
  ('Hebrews', 9, 11, 'But Christ having come as a high priest of the coming good things, through the greater and more perfect tabernacle, not made with hands, that is to say, not of this creation,'),
  ('Hebrews', 9, 12, 'nor yet through the blood of goats and calves, but through his own blood, entered in once for all into the Holy Place, having obtained eternal redemption.'),
  ('Hebrews', 9, 13, 'For if the blood of goats and bulls, and the ashes of a heifer sprinkling those who have been defiled, sanctify to the cleanness of the flesh,'),
  ('Hebrews', 9, 14, 'how much more will the blood of Christ, who through the eternal Spirit offered himself without defect to God, cleanse your conscience from dead works to serve the living God?'),
  ('Hebrews', 9, 15, 'For this reason he is the mediator of a new covenant, since a death has occurred for the redemption of the transgressions that were under the first covenant, that those who have been called may receive the promise of the eternal inheritance.'),
  ('Hebrews', 9, 16, 'For where a last will and testament is, there must of necessity be the death of him who made it.'),
  ('Hebrews', 9, 17, 'For a will is in force where there has been death, for it is never in force while he who made it lives.'),
  ('Hebrews', 9, 18, 'Therefore even the first covenant has not been dedicated without blood.'),
  ('Hebrews', 9, 19, 'For when every commandment had been spoken by Moses to all the people according to the law, he took the blood of the calves and the goats, with water and scarlet wool and hyssop, and sprinkled both the book itself and all the people,'),
  ('Hebrews', 9, 20, 'saying, “This is the blood of the covenant which God has commanded you.”'),
  ('Hebrews', 9, 21, 'He sprinkled the tabernacle and all the vessels of the ministry in the same way with the blood.'),
  ('Hebrews', 9, 22, 'According to the law, nearly everything is cleansed with blood, and apart from shedding of blood there is no remission.'),
  ('Hebrews', 9, 23, 'It was necessary therefore that the copies of the things in the heavens should be cleansed with these, but the heavenly things themselves with better sacrifices than these.'),
  ('Hebrews', 9, 24, 'For Christ hasn’t entered into holy places made with hands, which are representations of the true, but into heaven itself, now to appear in the presence of God for us;'),
  ('Hebrews', 9, 25, 'nor yet that he should offer himself often, as the high priest enters into the holy place year by year with blood not his own,'),
  ('Hebrews', 9, 26, 'or else he must have suffered often since the foundation of the world. But now once at the end of the ages, he has been revealed to put away sin by the sacrifice of himself.'),
  ('Hebrews', 9, 27, 'Inasmuch as it is appointed for men to die once, and after this, judgment,'),
  ('Hebrews', 9, 28, 'so Christ also, having been offered once to bear the sins of many, will appear a second time, not to deal with sin, but to save those who are eagerly waiting for him.'),
  ('Hebrews', 10, 1, 'For the law, having a shadow of the good to come, not the very image of the things, can never with the same sacrifices year by year, which they offer continually, make perfect those who draw near.'),
  ('Hebrews', 10, 2, 'Or else wouldn’t they have ceased to be offered, because the worshipers, having been once cleansed, would have had no more consciousness of sins?'),
  ('Hebrews', 10, 3, 'But in those sacrifices there is a yearly reminder of sins.'),
  ('Hebrews', 10, 4, 'For it is impossible that the blood of bulls and goats should take away sins.'),
  ('Hebrews', 10, 5, 'Therefore when he comes into the world, he says, “You didn’t desire sacrifice and offering, but you prepared a body for me.'),
  ('Hebrews', 10, 6, 'You had no pleasure in whole burnt offerings and sacrifices for sin.'),
  ('Hebrews', 10, 7, 'Then I said, ‘Behold, I have come (in the scroll of the book it is written of me) to do your will, O God.’”'),
  ('Hebrews', 10, 8, 'Previously saying, “Sacrifices and offerings and whole burnt offerings and sacrifices for sin you didn’t desire, neither had pleasure in them” (those which are offered according to the law),'),
  ('Hebrews', 10, 9, 'then he has said, “Behold, I have come to do your will.” He takes away the first, that he may establish the second,'),
  ('Hebrews', 10, 10, 'by which will we have been sanctified through the offering of the body of Jesus Christ once for all.'),
  ('Hebrews', 10, 11, 'Every priest indeed stands day by day serving and offering often the same sacrifices, which can never take away sins,'),
  ('Hebrews', 10, 12, 'but he, when he had offered one sacrifice for sins forever, sat down on the right hand of God,'),
  ('Hebrews', 10, 13, 'from that time waiting until his enemies are made the footstool of his feet.'),
  ('Hebrews', 10, 14, 'For by one offering he has perfected forever those who are being sanctified.'),
  ('Hebrews', 10, 15, 'The Holy Spirit also testifies to us, for after saying,'),
  ('Hebrews', 10, 16, '“This is the covenant that I will make with them after those days,” says the Lord, “I will put my laws on their heart, I will also write them on their mind;” then he says,'),
  ('Hebrews', 10, 17, '“I will remember their sins and their iniquities no more.”'),
  ('Hebrews', 10, 18, 'Now where remission of these is, there is no more offering for sin.'),
  ('Hebrews', 10, 19, 'Having therefore, brothers, boldness to enter into the holy place by the blood of Jesus,'),
  ('Hebrews', 10, 20, 'by the way which he dedicated for us, a new and living way, through the veil, that is to say, his flesh,'),
  ('Hebrews', 10, 21, 'and having a great priest over God’s house,'),
  ('Hebrews', 10, 22, 'let’s draw near with a true heart in fullness of faith, having our hearts sprinkled from an evil conscience and having our body washed with pure water,'),
  ('Hebrews', 10, 23, 'let’s hold fast the confession of our hope without wavering; for he who promised is faithful.'),
  ('Hebrews', 10, 24, 'Let’s consider how to provoke one another to love and good works,'),
  ('Hebrews', 10, 25, 'not forsaking our own assembling together, as the custom of some is, but exhorting one another, and so much the more as you see the Day approaching.'),
  ('Hebrews', 10, 26, 'For if we sin willfully after we have received the knowledge of the truth, there remains no more a sacrifice for sins,'),
  ('Hebrews', 10, 27, 'but a certain fearful expectation of judgment, and a fierceness of fire which will devour the adversaries.'),
  ('Hebrews', 10, 28, 'A man who disregards Moses’ law dies without compassion on the word of two or three witnesses.'),
  ('Hebrews', 10, 29, 'How much worse punishment do you think he will be judged worthy of who has trodden under foot the Son of God, and has counted the blood of the covenant with which he was sanctified an unholy thing, and has insulted the Spirit of grace?'),
  ('Hebrews', 10, 30, 'For we know him who said, “Vengeance belongs to me. I will repay,” says the Lord. Again, “The Lord will judge his people.”'),
  ('Hebrews', 10, 31, 'It is a fearful thing to fall into the hands of the living God.'),
  ('Hebrews', 10, 32, 'But remember the former days, in which, after you were enlightened, you endured a great struggle with sufferings:'),
  ('Hebrews', 10, 33, 'partly, being exposed to both reproaches and oppressions, and partly, becoming partakers with those who were treated so.'),
  ('Hebrews', 10, 34, 'For you both had compassion on me in my chains and joyfully accepted the plundering of your possessions, knowing that you have for yourselves a better possession and an enduring one in the heavens.'),
  ('Hebrews', 10, 35, 'Therefore don’t throw away your boldness, which has a great reward.'),
  ('Hebrews', 10, 36, 'For you need endurance so that, having done the will of God, you may receive the promise.'),
  ('Hebrews', 10, 37, '“In a very little while, he who comes will come and will not wait.'),
  ('Hebrews', 10, 38, 'But the righteous one will live by faith. If he shrinks back, my soul has no pleasure in him.”'),
  ('Hebrews', 10, 39, 'But we are not of those who shrink back to destruction, but of those who have faith to the saving of the soul.'),
  ('Hebrews', 11, 1, 'Now faith is assurance of things hoped for, proof of things not seen.'),
  ('Hebrews', 11, 2, 'For by this, the elders obtained approval.'),
  ('Hebrews', 11, 3, 'By faith we understand that the universe has been framed by the word of God, so that what is seen has not been made out of things which are visible.'),
  ('Hebrews', 11, 4, 'By faith Abel offered to God a more excellent sacrifice than Cain, through which he had testimony given to him that he was righteous, God testifying with respect to his gifts; and through it he, being dead, still speaks.'),
  ('Hebrews', 11, 5, 'By faith Enoch was taken away, so that he wouldn’t see death, and he was not found, because God translated him. For he has had testimony given to him that before his translation he had been well pleasing to God.'),
  ('Hebrews', 11, 6, 'Without faith it is impossible to be well pleasing to him, for he who comes to God must believe that he exists, and that he is a rewarder of those who seek him.'),
  ('Hebrews', 11, 7, 'By faith Noah, being warned about things not yet seen, moved with godly fear, prepared a ship for the saving of his house, through which he condemned the world and became heir of the righteousness which is according to faith.'),
  ('Hebrews', 11, 8, 'By faith Abraham, when he was called, obeyed to go out to the place which he was to receive for an inheritance. He went out, not knowing where he went.'),
  ('Hebrews', 11, 9, 'By faith he lived as an alien in the land of promise, as in a land not his own, dwelling in tents with Isaac and Jacob, the heirs with him of the same promise.'),
  ('Hebrews', 11, 10, 'For he was looking for the city which has foundations, whose builder and maker is God.'),
  ('Hebrews', 11, 11, 'By faith even Sarah herself received power to conceive, and she bore a child when she was past age, since she counted him faithful who had promised.'),
  ('Hebrews', 11, 12, 'Therefore as many as the stars of the sky in multitude, and as innumerable as the sand which is by the sea shore, were fathered by one man, and him as good as dead.'),
  ('Hebrews', 11, 13, 'These all died in faith, not having received the promises, but having seen them and embraced them from afar, and having confessed that they were strangers and pilgrims on the earth.'),
  ('Hebrews', 11, 14, 'For those who say such things make it clear that they are seeking a country of their own.'),
  ('Hebrews', 11, 15, 'If indeed they had been thinking of that country from which they went out, they would have had enough time to return.'),
  ('Hebrews', 11, 16, 'But now they desire a better country, that is, a heavenly one. Therefore God is not ashamed of them, to be called their God, for he has prepared a city for them.'),
  ('Hebrews', 11, 17, 'By faith, Abraham, being tested, offered up Isaac. Yes, he who had gladly received the promises was offering up his only born son,'),
  ('Hebrews', 11, 18, 'to whom it was said, “Your offspring will be accounted as from Isaac,”'),
  ('Hebrews', 11, 19, 'concluding that God is able to raise up even from the dead. Figuratively speaking, he also did receive him back from the dead.'),
  ('Hebrews', 11, 20, 'By faith Isaac blessed Jacob and Esau, even concerning things to come.'),
  ('Hebrews', 11, 21, 'By faith Jacob, when he was dying, blessed each of the sons of Joseph, and worshiped, leaning on the top of his staff.'),
  ('Hebrews', 11, 22, 'By faith Joseph, when his end was near, made mention of the departure of the children of Israel, and gave instructions concerning his bones.'),
  ('Hebrews', 11, 23, 'By faith Moses, when he was born, was hidden for three months by his parents, because they saw that he was a beautiful child; and they were not afraid of the king’s commandment.'),
  ('Hebrews', 11, 24, 'By faith Moses, when he had grown up, refused to be called the son of Pharaoh’s daughter,'),
  ('Hebrews', 11, 25, 'choosing rather to share ill treatment with God’s people than to enjoy the pleasures of sin for a time,'),
  ('Hebrews', 11, 26, 'considering the reproach of Christ greater riches than the treasures of Egypt; for he looked to the reward.'),
  ('Hebrews', 11, 27, 'By faith he left Egypt, not fearing the wrath of the king; for he endured, as seeing him who is invisible.'),
  ('Hebrews', 11, 28, 'By faith he kept the Passover and the sprinkling of the blood, that the destroyer of the firstborn should not touch them.'),
  ('Hebrews', 11, 29, 'By faith they passed through the Red Sea as on dry land. When the Egyptians tried to do so, they were swallowed up.'),
  ('Hebrews', 11, 30, 'By faith the walls of Jericho fell down after they had been encircled for seven days.'),
  ('Hebrews', 11, 31, 'By faith Rahab the prostitute didn’t perish with those who were disobedient, having received the spies in peace.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Hebrews', 11, 32, 'What more shall I say? For the time would fail me if I told of Gideon, Barak, Samson, Jephthah, David, Samuel, and the prophets—'),
  ('Hebrews', 11, 33, 'who through faith subdued kingdoms, worked out righteousness, obtained promises, stopped the mouths of lions,'),
  ('Hebrews', 11, 34, 'quenched the power of fire, escaped the edge of the sword, from weakness were made strong, grew mighty in war, and caused foreign armies to flee.'),
  ('Hebrews', 11, 35, 'Women received their dead by resurrection. Others were tortured, not accepting their deliverance, that they might obtain a better resurrection.'),
  ('Hebrews', 11, 36, 'Others were tried by mocking and scourging, yes, moreover by bonds and imprisonment.'),
  ('Hebrews', 11, 37, 'They were stoned. They were sawn apart. They were tempted. They were slain with the sword. They went around in sheep skins and in goat skins; being destitute, afflicted, ill-treated—'),
  ('Hebrews', 11, 38, 'of whom the world was not worthy—wandering in deserts, mountains, caves, and the holes of the earth.'),
  ('Hebrews', 11, 39, 'These all, having been commended for their faith, didn’t receive the promise,'),
  ('Hebrews', 11, 40, 'God having provided some better thing concerning us, so that apart from us they should not be made perfect.'),
  ('Hebrews', 12, 1, 'Therefore let’s also, seeing we are surrounded by so great a cloud of witnesses, lay aside every weight and the sin which so easily entangles us, and let’s run with perseverance the race that is set before us,'),
  ('Hebrews', 12, 2, 'looking to Jesus, the author and perfecter of faith, who for the joy that was set before him endured the cross, despising its shame, and has sat down at the right hand of the throne of God.'),
  ('Hebrews', 12, 3, 'For consider him who has endured such contradiction of sinners against himself, that you don’t grow weary, fainting in your souls.'),
  ('Hebrews', 12, 4, 'You have not yet resisted to blood, striving against sin.'),
  ('Hebrews', 12, 5, 'You have forgotten the exhortation which reasons with you as with children, “My son, don’t take lightly the chastening of the Lord, nor faint when you are reproved by him;'),
  ('Hebrews', 12, 6, 'for whom the Lord loves, he disciplines, and chastises every son whom he receives.”'),
  ('Hebrews', 12, 7, 'It is for discipline that you endure. God deals with you as with children, for what son is there whom his father doesn’t discipline?'),
  ('Hebrews', 12, 8, 'But if you are without discipline, of which all have been made partakers, then you are illegitimate, and not children.'),
  ('Hebrews', 12, 9, 'Furthermore, we had the fathers of our flesh to chasten us, and we paid them respect. Shall we not much rather be in subjection to the Father of spirits and live?'),
  ('Hebrews', 12, 10, 'For they indeed for a few days disciplined us as seemed good to them, but he for our profit, that we may be partakers of his holiness.'),
  ('Hebrews', 12, 11, 'All chastening seems for the present to be not joyous but grievous; yet afterward it yields the peaceful fruit of righteousness to those who have been trained by it.'),
  ('Hebrews', 12, 12, 'Therefore lift up the hands that hang down and the feeble knees,'),
  ('Hebrews', 12, 13, 'and make straight paths for your feet, so what is lame may not be dislocated, but rather be healed.'),
  ('Hebrews', 12, 14, 'Follow after peace with all men, and the sanctification without which no man will see the Lord,'),
  ('Hebrews', 12, 15, 'looking carefully lest there be any man who falls short of the grace of God, lest any root of bitterness springing up trouble you and many be defiled by it,'),
  ('Hebrews', 12, 16, 'lest there be any sexually immoral person or profane person, like Esau, who sold his birthright for one meal.'),
  ('Hebrews', 12, 17, 'For you know that even when he afterward desired to inherit the blessing, he was rejected, for he found no place for a change of mind though he sought it diligently with tears.'),
  ('Hebrews', 12, 18, 'For you have not come to a mountain that might be touched and that burned with fire, and to blackness, darkness, storm,'),
  ('Hebrews', 12, 19, 'the sound of a trumpet, and the voice of words; which those who heard it begged that not one more word should be spoken to them,'),
  ('Hebrews', 12, 20, 'for they could not stand that which was commanded, “If even an animal touches the mountain, it shall be stoned”.'),
  ('Hebrews', 12, 21, 'So fearful was the appearance that Moses said, “I am terrified and trembling.”'),
  ('Hebrews', 12, 22, 'But you have come to Mount Zion and to the city of the living God, the heavenly Jerusalem, and to innumerable multitudes of angels,'),
  ('Hebrews', 12, 23, 'to the festal gathering and assembly of the firstborn who are enrolled in heaven, to God the Judge of all, to the spirits of just men made perfect,'),
  ('Hebrews', 12, 24, 'to Jesus, the mediator of a new covenant, and to the blood of sprinkling that speaks better than that of Abel.'),
  ('Hebrews', 12, 25, 'See that you don’t refuse him who speaks. For if they didn’t escape when they refused him who warned on the earth, how much more will we not escape who turn away from him who warns from heaven,'),
  ('Hebrews', 12, 26, 'whose voice shook the earth then, but now he has promised, saying, “Yet once more I will shake not only the earth, but also the heavens.”'),
  ('Hebrews', 12, 27, 'This phrase, “Yet once more” signifies the removing of those things that are shaken, as of things that have been made, that those things which are not shaken may remain.'),
  ('Hebrews', 12, 28, 'Therefore, receiving a Kingdom that can’t be shaken, let’s have grace, through which we serve God acceptably, with reverence and awe,'),
  ('Hebrews', 12, 29, 'for our God is a consuming fire.'),
  ('Hebrews', 13, 1, 'Let brotherly love continue.'),
  ('Hebrews', 13, 2, 'Don’t forget to show hospitality to strangers, for in doing so, some have entertained angels without knowing it.'),
  ('Hebrews', 13, 3, 'Remember those who are in bonds, as bound with them, and those who are ill-treated, since you are also in the body.'),
  ('Hebrews', 13, 4, 'Let marriage be held in honor among all, and let the bed be undefiled; but God will judge the sexually immoral and adulterers.'),
  ('Hebrews', 13, 5, 'Be free from the love of money, content with such things as you have, for he has said, “I will in no way leave you, neither will I in any way forsake you.”'),
  ('Hebrews', 13, 6, 'So that with good courage we say, “The Lord is my helper. I will not fear. What can man do to me?”'),
  ('Hebrews', 13, 7, 'Remember your leaders, men who spoke to you the word of God, and considering the results of their conduct, imitate their faith.'),
  ('Hebrews', 13, 8, 'Jesus Christ is the same yesterday, today, and forever.'),
  ('Hebrews', 13, 9, 'Don’t be carried away by various and strange teachings, for it is good that the heart be established by grace, not by foods, through which those who were so occupied were not benefited.'),
  ('Hebrews', 13, 10, 'We have an altar from which those who serve the holy tabernacle have no right to eat.'),
  ('Hebrews', 13, 11, 'For the bodies of those animals, whose blood is brought into the holy place by the high priest as an offering for sin, are burned outside of the camp.'),
  ('Hebrews', 13, 12, 'Therefore Jesus also, that he might sanctify the people through his own blood, suffered outside of the gate.'),
  ('Hebrews', 13, 13, 'Let’s therefore go out to him outside of the camp, bearing his reproach.'),
  ('Hebrews', 13, 14, 'For we don’t have here an enduring city, but we seek that which is to come.'),
  ('Hebrews', 13, 15, 'Through him, then, let’s offer up a sacrifice of praise to God continually, that is, the fruit of lips which proclaim allegiance to his name.'),
  ('Hebrews', 13, 16, 'But don’t forget to be doing good and sharing, for with such sacrifices God is well pleased.'),
  ('Hebrews', 13, 17, 'Obey your leaders and submit to them, for they watch on behalf of your souls, as those who will give account, that they may do this with joy and not with groaning, for that would be unprofitable for you.'),
  ('Hebrews', 13, 18, 'Pray for us, for we are persuaded that we have a good conscience, desiring to live honorably in all things.'),
  ('Hebrews', 13, 19, 'I strongly urge you to do this, that I may be restored to you sooner.'),
  ('Hebrews', 13, 20, 'Now may the God of peace, who brought again from the dead the great shepherd of the sheep with the blood of an eternal covenant, our Lord Jesus,'),
  ('Hebrews', 13, 21, 'make you complete in every good work to do his will, working in you that which is well pleasing in his sight, through Jesus Christ, to whom be the glory forever and ever. Amen.'),
  ('Hebrews', 13, 22, 'But I exhort you, brothers, endure the word of exhortation, for I have written to you in few words.'),
  ('Hebrews', 13, 23, 'Know that our brother Timothy has been freed, with whom, if he comes shortly, I will see you.'),
  ('Hebrews', 13, 24, 'Greet all of your leaders and all the saints. The Italians greet you.'),
  ('Hebrews', 13, 25, 'Grace be with you all. Amen.'),
  ('James', 1, 1, 'James, a servant of God and of the Lord Jesus Christ, to the twelve tribes which are in the Dispersion: Greetings.'),
  ('James', 1, 2, 'Count it all joy, my brothers, when you fall into various temptations,'),
  ('James', 1, 3, 'knowing that the testing of your faith produces endurance.'),
  ('James', 1, 4, 'Let endurance have its perfect work, that you may be perfect and complete, lacking in nothing.'),
  ('James', 1, 5, 'But if any of you lacks wisdom, let him ask of God, who gives to all liberally and without reproach, and it will be given to him.'),
  ('James', 1, 6, 'But let him ask in faith, without any doubting, for he who doubts is like a wave of the sea, driven by the wind and tossed.'),
  ('James', 1, 7, 'For that man shouldn’t think that he will receive anything from the Lord.'),
  ('James', 1, 8, 'He is a double-minded man, unstable in all his ways.'),
  ('James', 1, 9, 'Let the brother in humble circumstances glory in his high position;'),
  ('James', 1, 10, 'and the rich, in that he is made humble, because like the flower in the grass, he will pass away.'),
  ('James', 1, 11, 'For the sun arises with the scorching wind and withers the grass; and the flower in it falls, and the beauty of its appearance perishes. So the rich man will also fade away in his pursuits.'),
  ('James', 1, 12, 'Blessed is a person who endures temptation, for when he has been approved, he will receive the crown of life which the Lord promised to those who love him.'),
  ('James', 1, 13, 'Let no man say when he is tempted, “I am tempted by God,” for God can’t be tempted by evil, and he himself tempts no one.'),
  ('James', 1, 14, 'But each one is tempted when he is drawn away by his own lust and enticed.'),
  ('James', 1, 15, 'Then the lust, when it has conceived, bears sin. The sin, when it is full grown, produces death.'),
  ('James', 1, 16, 'Don’t be deceived, my beloved brothers.'),
  ('James', 1, 17, 'Every good gift and every perfect gift is from above, coming down from the Father of lights, with whom can be no variation nor turning shadow.'),
  ('James', 1, 18, 'Of his own will he gave birth to us by the word of truth, that we should be a kind of first fruits of his creatures.'),
  ('James', 1, 19, 'So, then, my beloved brothers, let every man be swift to hear, slow to speak, and slow to anger;'),
  ('James', 1, 20, 'for the anger of man doesn’t produce the righteousness of God.'),
  ('James', 1, 21, 'Therefore, putting away all filthiness and overflowing of wickedness, receive with humility the implanted word, which is able to save your souls.'),
  ('James', 1, 22, 'But be doers of the word, and not only hearers, deluding your own selves.'),
  ('James', 1, 23, 'For if anyone is a hearer of the word and not a doer, he is like a man looking at his natural face in a mirror;'),
  ('James', 1, 24, 'for he sees himself, and goes away, and immediately forgets what kind of man he was.'),
  ('James', 1, 25, 'But he who looks into the perfect law of freedom and continues, not being a hearer who forgets but a doer of the work, this man will be blessed in what he does.'),
  ('James', 1, 26, 'If anyone among you thinks himself to be religious while he doesn’t bridle his tongue, but deceives his heart, this man’s religion is worthless.'),
  ('James', 1, 27, 'Pure religion and undefiled before our God and Father is this: to visit the fatherless and widows in their affliction, and to keep oneself unstained by the world.'),
  ('James', 2, 1, 'My brothers, don’t hold the faith of our glorious Lord Jesus Christ with partiality.'),
  ('James', 2, 2, 'For if a man with a gold ring, in fine clothing, comes into your synagogue, and a poor man in filthy clothing also comes in,'),
  ('James', 2, 3, 'and you pay special attention to him who wears the fine clothing and say, “Sit here in a good place;” and you tell the poor man, “Stand there,” or “Sit by my footstool”'),
  ('James', 2, 4, 'haven’t you shown partiality among yourselves, and become judges with evil thoughts?'),
  ('James', 2, 5, 'Listen, my beloved brothers. Didn’t God choose those who are poor in this world to be rich in faith and heirs of the Kingdom which he promised to those who love him?'),
  ('James', 2, 6, 'But you have dishonored the poor man. Don’t the rich oppress you and personally drag you before the courts?'),
  ('James', 2, 7, 'Don’t they blaspheme the honorable name by which you are called?'),
  ('James', 2, 8, 'However, if you fulfill the royal law according to the Scripture, “You shall love your neighbor as yourself,” you do well.'),
  ('James', 2, 9, 'But if you show partiality, you commit sin, being convicted by the law as transgressors.'),
  ('James', 2, 10, 'For whoever keeps the whole law, and yet stumbles in one point, he has become guilty of all.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('James', 2, 11, 'For he who said, “Do not commit adultery,” also said, “Do not commit murder.” Now if you do not commit adultery but do murder, you have become a transgressor of the law.'),
  ('James', 2, 12, 'So speak and so do as men who are to be judged by the law of freedom.'),
  ('James', 2, 13, 'For judgment is without mercy to him who has shown no mercy. Mercy triumphs over judgment.'),
  ('James', 2, 14, 'What good is it, my brothers, if a man says he has faith, but has no works? Can faith save him?'),
  ('James', 2, 15, 'And if a brother or sister is naked and in lack of daily food,'),
  ('James', 2, 16, 'and one of you tells them, “Go in peace. Be warmed and filled;” yet you didn’t give them the things the body needs, what good is it?'),
  ('James', 2, 17, 'Even so faith, if it has no works, is dead in itself.'),
  ('James', 2, 18, 'Yes, a man will say, “You have faith, and I have works.” Show me your faith without works, and I will show you my faith by my works.'),
  ('James', 2, 19, 'You believe that God is one. You do well. The demons also believe—and shudder.'),
  ('James', 2, 20, 'But do you want to know, vain man, that faith apart from works is dead?'),
  ('James', 2, 21, 'Wasn’t Abraham our father justified by works, in that he offered up Isaac his son on the altar?'),
  ('James', 2, 22, 'You see that faith worked with his works, and by works faith was perfected.'),
  ('James', 2, 23, 'So the Scripture was fulfilled which says, “Abraham believed God, and it was accounted to him as righteousness,” and he was called the friend of God.'),
  ('James', 2, 24, 'You see then that by works a man is justified, and not only by faith.'),
  ('James', 2, 25, 'In the same way, wasn’t Rahab the prostitute also justified by works when she received the messengers and sent them out another way?'),
  ('James', 2, 26, 'For as the body apart from the spirit is dead, even so faith apart from works is dead.'),
  ('James', 3, 1, 'Let not many of you be teachers, my brothers, knowing that we will receive heavier judgment.'),
  ('James', 3, 2, 'For we all stumble in many things. Anyone who doesn’t stumble in word is a perfect person, able to bridle the whole body also.'),
  ('James', 3, 3, 'Indeed, we put bits into the horses’ mouths so that they may obey us, and we guide their whole body.'),
  ('James', 3, 4, 'Behold, the ships also, though they are so big and are driven by fierce winds, are yet guided by a very small rudder, wherever the pilot desires.'),
  ('James', 3, 5, 'So the tongue is also a little member, and boasts great things. See how a small fire can spread to a large forest!'),
  ('James', 3, 6, 'And the tongue is a fire. The world of iniquity among our members is the tongue, which defiles the whole body, and sets on fire the course of nature, and is set on fire by Gehenna.'),
  ('James', 3, 7, 'For every kind of animal, bird, creeping thing, and sea creature is tamed, and has been tamed by mankind;'),
  ('James', 3, 8, 'but nobody can tame the tongue. It is a restless evil, full of deadly poison.'),
  ('James', 3, 9, 'With it we bless our God and Father, and with it we curse men who are made in the image of God.'),
  ('James', 3, 10, 'Out of the same mouth comes blessing and cursing. My brothers, these things ought not to be so.'),
  ('James', 3, 11, 'Does a spring send out from the same opening fresh and bitter water?'),
  ('James', 3, 12, 'Can a fig tree, my brothers, yield olives, or a vine figs? Thus no spring yields both salt water and fresh water.'),
  ('James', 3, 13, 'Who is wise and understanding among you? Let him show by his good conduct that his deeds are done in gentleness of wisdom.'),
  ('James', 3, 14, 'But if you have bitter jealousy and selfish ambition in your heart, don’t boast and don’t lie against the truth.'),
  ('James', 3, 15, 'This wisdom is not that which comes down from above, but is earthly, sensual, and demonic.'),
  ('James', 3, 16, 'For where jealousy and selfish ambition are, there is confusion and every evil deed.'),
  ('James', 3, 17, 'But the wisdom that is from above is first pure, then peaceful, gentle, reasonable, full of mercy and good fruits, without partiality, and without hypocrisy.'),
  ('James', 3, 18, 'Now the fruit of righteousness is sown in peace by those who make peace.'),
  ('James', 4, 1, 'Where do wars and fightings among you come from? Don’t they come from your pleasures that war in your members?'),
  ('James', 4, 2, 'You lust, and don’t have. You murder and covet, and can’t obtain. You fight and make war. You don’t have, because you don’t ask.'),
  ('James', 4, 3, 'You ask, and don’t receive, because you ask with wrong motives, so that you may spend it on your pleasures.'),
  ('James', 4, 4, 'You adulterers and adulteresses, don’t you know that friendship with the world is hostility toward God? Whoever therefore wants to be a friend of the world makes himself an enemy of God.'),
  ('James', 4, 5, 'Or do you think that the Scripture says in vain, “The Spirit who lives in us yearns jealously”?'),
  ('James', 4, 6, 'But he gives more grace. Therefore it says, “God resists the proud, but gives grace to the humble.”'),
  ('James', 4, 7, 'Be subject therefore to God. Resist the devil, and he will flee from you.'),
  ('James', 4, 8, 'Draw near to God, and he will draw near to you. Cleanse your hands, you sinners. Purify your hearts, you double-minded.'),
  ('James', 4, 9, 'Lament, mourn, and weep. Let your laughter be turned to mourning and your joy to gloom.'),
  ('James', 4, 10, 'Humble yourselves in the sight of the Lord, and he will exalt you.'),
  ('James', 4, 11, 'Don’t speak against one another, brothers. He who speaks against a brother and judges his brother, speaks against the law and judges the law. But if you judge the law, you are not a doer of the law but a judge.'),
  ('James', 4, 12, 'Only one is the lawgiver, who is able to save and to destroy. But who are you to judge another?'),
  ('James', 4, 13, 'Come now, you who say, “Today or tomorrow let’s go into this city and spend a year there, trade, and make a profit.”'),
  ('James', 4, 14, 'Yet you don’t know what your life will be like tomorrow. For what is your life? For you are a vapor that appears for a little time and then vanishes away.'),
  ('James', 4, 15, 'For you ought to say, “If the Lord wills, we will both live, and do this or that.”'),
  ('James', 4, 16, 'But now you glory in your boasting. All such boasting is evil.'),
  ('James', 4, 17, 'To him therefore who knows to do good and doesn’t do it, to him it is sin.'),
  ('James', 5, 1, 'Come now, you rich, weep and howl for your miseries that are coming on you.'),
  ('James', 5, 2, 'Your riches are corrupted and your garments are moth-eaten.'),
  ('James', 5, 3, 'Your gold and your silver are corroded, and their corrosion will be for a testimony against you and will eat your flesh like fire. You have laid up your treasure in the last days.'),
  ('James', 5, 4, 'Behold, the wages of the laborers who mowed your fields, which you have kept back by fraud, cry out; and the cries of those who reaped have entered into the ears of the Lord of Armies.'),
  ('James', 5, 5, 'You have lived in luxury on the earth, and taken your pleasure. You have nourished your hearts as in a day of slaughter.'),
  ('James', 5, 6, 'You have condemned and you have murdered the righteous one. He doesn’t resist you.'),
  ('James', 5, 7, 'Be patient therefore, brothers, until the coming of the Lord. Behold, the farmer waits for the precious fruit of the earth, being patient over it, until it receives the early and late rain.'),
  ('James', 5, 8, 'You also be patient. Establish your hearts, for the coming of the Lord is at hand.'),
  ('James', 5, 9, 'Don’t grumble, brothers, against one another, so that you won’t be judged. Behold, the judge stands at the door.'),
  ('James', 5, 10, 'Take, brothers, for an example of suffering and of perseverance, the prophets who spoke in the name of the Lord.'),
  ('James', 5, 11, 'Behold, we call them blessed who endured. You have heard of the perseverance of Job and have seen the Lord in the outcome, and how the Lord is full of compassion and mercy.'),
  ('James', 5, 12, 'But above all things, my brothers, don’t swear—not by heaven, or by the earth, or by any other oath; but let your “yes” be “yes”, and your “no”, “no”, so that you don’t fall into hypocrisy.'),
  ('James', 5, 13, 'Is any among you suffering? Let him pray. Is any cheerful? Let him sing praises.'),
  ('James', 5, 14, 'Is any among you sick? Let him call for the elders of the assembly, and let them pray over him, anointing him with oil in the name of the Lord;'),
  ('James', 5, 15, 'and the prayer of faith will heal him who is sick, and the Lord will raise him up. If he has committed sins, he will be forgiven.'),
  ('James', 5, 16, 'Confess your sins to one another and pray for one another, that you may be healed. The insistent prayer of a righteous person is powerfully effective.'),
  ('James', 5, 17, 'Elijah was a man with a nature like ours, and he prayed earnestly that it might not rain, and it didn’t rain on the earth for three years and six months.'),
  ('James', 5, 18, 'He prayed again, and the sky gave rain, and the earth produced its fruit.'),
  ('James', 5, 19, 'Brothers, if any among you wanders from the truth and someone turns him back,'),
  ('James', 5, 20, 'let him know that he who turns a sinner from the error of his way will save a soul from death and will cover a multitude of sins.'),
  ('1 Peter', 1, 1, 'Peter, an apostle of Jesus Christ, to the chosen ones who are living as foreigners in the Dispersion in Pontus, Galatia, Cappadocia, Asia, and Bithynia,'),
  ('1 Peter', 1, 2, 'according to the foreknowledge of God the Father, in sanctification of the Spirit, that you may obey Jesus Christ and be sprinkled with his blood: Grace to you and peace be multiplied.'),
  ('1 Peter', 1, 3, 'Blessed be the God and Father of our Lord Jesus Christ, who according to his great mercy caused us to be born again to a living hope through the resurrection of Jesus Christ from the dead,'),
  ('1 Peter', 1, 4, 'to an incorruptible and undefiled inheritance that doesn’t fade away, reserved in Heaven for you,'),
  ('1 Peter', 1, 5, 'who by the power of God are guarded through faith for a salvation ready to be revealed in the last time.'),
  ('1 Peter', 1, 6, 'In this you greatly rejoice, though now for a little while, if need be, you have been grieved in various trials,'),
  ('1 Peter', 1, 7, 'that the proof of your faith, which is more precious than gold that perishes, even though it is tested by fire, may be found to result in praise, glory, and honor at the revelation of Jesus Christ—'),
  ('1 Peter', 1, 8, 'whom, not having known, you love. In him, though now you don’t see him, yet believing, you rejoice greatly with joy that is unspeakable and full of glory,'),
  ('1 Peter', 1, 9, 'receiving the result of your faith, the salvation of your souls.'),
  ('1 Peter', 1, 10, 'Concerning this salvation, the prophets sought and searched diligently. They prophesied of the grace that would come to you,'),
  ('1 Peter', 1, 11, 'searching for who or what kind of time the Spirit of Christ which was in them pointed to when he predicted the sufferings of Christ and the glories that would follow them.'),
  ('1 Peter', 1, 12, 'To them it was revealed that they served not themselves, but you, in these things, which now have been announced to you through those who preached the Good News to you by the Holy Spirit sent out from heaven; which things angels desire to look into.'),
  ('1 Peter', 1, 13, 'Therefore prepare your minds for action. Be sober, and set your hope fully on the grace that will be brought to you at the revelation of Jesus Christ—'),
  ('1 Peter', 1, 14, 'as children of obedience, not conforming yourselves according to your former lusts as in your ignorance,'),
  ('1 Peter', 1, 15, 'but just as he who called you is holy, you yourselves also be holy in all of your behavior,'),
  ('1 Peter', 1, 16, 'because it is written, “You shall be holy, for I am holy.”'),
  ('1 Peter', 1, 17, 'If you call on him as Father, who without respect of persons judges according to each man’s work, pass the time of your living as foreigners here in reverent fear,'),
  ('1 Peter', 1, 18, 'knowing that you were redeemed, not with corruptible things like silver or gold, from the useless way of life handed down from your fathers,'),
  ('1 Peter', 1, 19, 'but with precious blood, as of a lamb without blemish or spot, the blood of Christ,'),
  ('1 Peter', 1, 20, 'who was foreknown indeed before the foundation of the world, but was revealed in this last age for your sake,'),
  ('1 Peter', 1, 21, 'who through him are believers in God, who raised him from the dead and gave him glory, so that your faith and hope might be in God.'),
  ('1 Peter', 1, 22, 'Seeing you have purified your souls in your obedience to the truth through the Spirit in sincere brotherly affection, love one another from the heart fervently,'),
  ('1 Peter', 1, 23, 'having been born again, not of corruptible seed, but of incorruptible, through the word of God, which lives and remains forever.'),
  ('1 Peter', 1, 24, 'For, “All flesh is like grass, and all of man’s glory like the flower in the grass. The grass withers, and its flower falls;'),
  ('1 Peter', 1, 25, 'but the Lord’s word endures forever.” This is the word of Good News which was preached to you.'),
  ('1 Peter', 2, 1, 'Putting away therefore all wickedness, all deceit, hypocrisies, envies, and all evil speaking,'),
  ('1 Peter', 2, 2, 'as newborn babies, long for the pure spiritual milk, that with it you may grow,'),
  ('1 Peter', 2, 3, 'if indeed you have tasted that the Lord is gracious.'),
  ('1 Peter', 2, 4, 'Come to him, a living stone, rejected indeed by men, but chosen by God, precious.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 Peter', 2, 5, 'You also as living stones are built up as a spiritual house, to be a holy priesthood, to offer up spiritual sacrifices, acceptable to God through Jesus Christ.'),
  ('1 Peter', 2, 6, 'Because it is contained in Scripture, “Behold, I lay in Zion a chief cornerstone, chosen and precious. He who believes in him will not be disappointed.”'),
  ('1 Peter', 2, 7, 'For you who believe therefore is the honor, but for those who are disobedient, “The stone which the builders rejected has become the chief cornerstone,”'),
  ('1 Peter', 2, 8, 'and, “a stumbling stone and a rock of offense.” For they stumble at the word, being disobedient, to which also they were appointed.'),
  ('1 Peter', 2, 9, 'But you are a chosen race, a royal priesthood, a holy nation, a people for God’s own possession, that you may proclaim the excellence of him who called you out of darkness into his marvelous light.'),
  ('1 Peter', 2, 10, 'In the past, you were not a people, but now are God’s people, who had not obtained mercy, but now have obtained mercy.'),
  ('1 Peter', 2, 11, 'Beloved, I beg you as foreigners and pilgrims to abstain from fleshly lusts which war against the soul,'),
  ('1 Peter', 2, 12, 'having good behavior among the nations, so in that of which they speak against you as evildoers, they may see your good works and glorify God in the day of visitation.'),
  ('1 Peter', 2, 13, 'Therefore subject yourselves to every ordinance of man for the Lord’s sake: whether to the king, as supreme,'),
  ('1 Peter', 2, 14, 'or to governors, as sent by him for vengeance on evildoers and for praise to those who do well.'),
  ('1 Peter', 2, 15, 'For this is the will of God, that by well-doing you should put to silence the ignorance of foolish men.'),
  ('1 Peter', 2, 16, 'Live as free people, yet not using your freedom for a cloak of wickedness, but as bondservants of God.'),
  ('1 Peter', 2, 17, 'Honor all men. Love the brotherhood. Fear God. Honor the king.'),
  ('1 Peter', 2, 18, 'Servants, be in subjection to your masters with all respect, not only to the good and gentle, but also to the wicked.'),
  ('1 Peter', 2, 19, 'For it is commendable if someone endures pain, suffering unjustly, because of conscience toward God.'),
  ('1 Peter', 2, 20, 'For what glory is it if, when you sin, you patiently endure beating? But if when you do well, you patiently endure suffering, this is commendable with God.'),
  ('1 Peter', 2, 21, 'For you were called to this, because Christ also suffered for us, leaving you an example, that you should follow his steps,'),
  ('1 Peter', 2, 22, 'who didn’t sin, “neither was deceit found in his mouth.”'),
  ('1 Peter', 2, 23, 'When he was cursed, he didn’t curse back. When he suffered, he didn’t threaten, but committed himself to him who judges righteously.'),
  ('1 Peter', 2, 24, 'He himself bore our sins in his body on the tree, that we, having died to sins, might live to righteousness. You were healed by his wounds.'),
  ('1 Peter', 2, 25, 'For you were going astray like sheep; but now you have returned to the Shepherd and Overseer of your souls.'),
  ('1 Peter', 3, 1, 'In the same way, wives, be in subjection to your own husbands, so that, even if any don’t obey the Word, they may be won by the behavior of their wives without a word,'),
  ('1 Peter', 3, 2, 'seeing your pure behavior in fear.'),
  ('1 Peter', 3, 3, 'Let your beauty come not from the outward adorning of braiding your hair, and of wearing gold ornaments or of putting on fine clothing,'),
  ('1 Peter', 3, 4, 'but from the hidden person of the heart, in the incorruptible adornment of a gentle and quiet spirit, which is very precious in God’s sight.'),
  ('1 Peter', 3, 5, 'For this is how in the past the holy women who hoped in God also adorned themselves, being in subjection to their own husbands.'),
  ('1 Peter', 3, 6, 'So Sarah obeyed Abraham, calling him lord, whose children you now are if you do well and are not put in fear by any terror.'),
  ('1 Peter', 3, 7, 'You husbands, in the same way, live with your wives according to knowledge, giving honor to the woman as to the weaker vessel, as also being joint heirs of the grace of life, that your prayers may not be hindered.'),
  ('1 Peter', 3, 8, 'Finally, all of you be like-minded, compassionate, loving as brothers, tenderhearted, courteous,'),
  ('1 Peter', 3, 9, 'not rendering evil for evil or insult for insult; but instead blessing, knowing that you were called to this, that you may inherit a blessing.'),
  ('1 Peter', 3, 10, 'For, “He who would love life and see good days, let him keep his tongue from evil and his lips from speaking deceit.'),
  ('1 Peter', 3, 11, 'Let him turn away from evil and do good. Let him seek peace and pursue it.'),
  ('1 Peter', 3, 12, 'For the eyes of the Lord are on the righteous, and his ears open to their prayer; but the face of the Lord is against those who do evil.”'),
  ('1 Peter', 3, 13, 'Now who will harm you if you become imitators of that which is good?'),
  ('1 Peter', 3, 14, 'But even if you should suffer for righteousness’ sake, you are blessed. “Don’t fear what they fear, neither be troubled.”'),
  ('1 Peter', 3, 15, 'But sanctify the Lord God in your hearts. Always be ready to give an answer to everyone who asks you a reason concerning the hope that is in you, with humility and fear,'),
  ('1 Peter', 3, 16, 'having a good conscience. Thus, while you are spoken against as evildoers, they may be disappointed who curse your good way of life in Christ.'),
  ('1 Peter', 3, 17, 'For it is better, if it is God’s will, that you suffer for doing what is right than for doing evil.'),
  ('1 Peter', 3, 18, 'Because Christ also suffered for sins once, the righteous for the unrighteous, that he might bring you to God, being put to death in the flesh, but made alive in the Spirit,'),
  ('1 Peter', 3, 19, 'in whom he also went and preached to the spirits in prison,'),
  ('1 Peter', 3, 20, 'who before were disobedient when God waited patiently in the days of Noah while the ship was being built. In it, few, that is, eight souls, were saved through water.'),
  ('1 Peter', 3, 21, 'This is a symbol of baptism, which now saves you—not the putting away of the filth of the flesh, but the answer of a good conscience toward God—through the resurrection of Jesus Christ,'),
  ('1 Peter', 3, 22, 'who is at the right hand of God, having gone into heaven, angels and authorities and powers being made subject to him.'),
  ('1 Peter', 4, 1, 'Therefore, since Christ suffered for us in the flesh, arm yourselves also with the same mind; for he who has suffered in the flesh has ceased from sin,'),
  ('1 Peter', 4, 2, 'that you no longer should live the rest of your time in the flesh for the lusts of men, but for the will of God.'),
  ('1 Peter', 4, 3, 'For we have spent enough of our past time doing the desire of the Gentiles, and having walked in lewdness, lusts, drunken binges, orgies, carousings, and abominable idolatries.'),
  ('1 Peter', 4, 4, 'They think it is strange that you don’t run with them into the same excess of riot, speaking evil of you.'),
  ('1 Peter', 4, 5, 'They will give account to him who is ready to judge the living and the dead.'),
  ('1 Peter', 4, 6, 'For to this end the Good News was preached even to the dead, that they might be judged indeed as men in the flesh, but live as to God in the spirit.'),
  ('1 Peter', 4, 7, 'But the end of all things is near. Therefore be of sound mind, self-controlled, and sober in prayer.'),
  ('1 Peter', 4, 8, 'And above all things be earnest in your love among yourselves, for love covers a multitude of sins.'),
  ('1 Peter', 4, 9, 'Be hospitable to one another without grumbling.'),
  ('1 Peter', 4, 10, 'As each has received a gift, employ it in serving one another, as good managers of the grace of God in its various forms.'),
  ('1 Peter', 4, 11, 'If anyone speaks, let it be as it were the very words of God. If anyone serves, let it be as of the strength which God supplies, that in all things God may be glorified through Jesus Christ, to whom belong the glory and the dominion forever and ever. Amen.'),
  ('1 Peter', 4, 12, 'Beloved, don’t be astonished at the fiery trial which has come upon you to test you, as though a strange thing happened to you.'),
  ('1 Peter', 4, 13, 'But because you are partakers of Christ’s sufferings, rejoice, that at the revelation of his glory you also may rejoice with exceeding joy.'),
  ('1 Peter', 4, 14, 'If you are insulted for the name of Christ, you are blessed, because the Spirit of glory and of God rests on you. On their part he is blasphemed, but on your part he is glorified.'),
  ('1 Peter', 4, 15, 'But let none of you suffer as a murderer, or a thief, or an evil doer, or a meddler in other men’s matters.'),
  ('1 Peter', 4, 16, 'But if one of you suffers for being a Christian, let him not be ashamed; but let him glorify God in this matter.'),
  ('1 Peter', 4, 17, 'For the time has come for judgment to begin with the household of God. If it begins first with us, what will happen to those who don’t obey the Good News of God?'),
  ('1 Peter', 4, 18, '“If it is hard for the righteous to be saved, what will happen to the ungodly and the sinner?”'),
  ('1 Peter', 4, 19, 'Therefore let them also who suffer according to the will of God in doing good entrust their souls to him, as to a faithful Creator.'),
  ('1 Peter', 5, 1, 'Therefore I exhort the elders among you, as a fellow elder and a witness of the sufferings of Christ, and who will also share in the glory that will be revealed:'),
  ('1 Peter', 5, 2, 'shepherd the flock of God which is among you, exercising the oversight, not under compulsion, but voluntarily; not for dishonest gain, but willingly;'),
  ('1 Peter', 5, 3, 'not as lording it over those entrusted to you, but making yourselves examples to the flock.'),
  ('1 Peter', 5, 4, 'When the chief Shepherd is revealed, you will receive the crown of glory that doesn’t fade away.'),
  ('1 Peter', 5, 5, 'Likewise, you younger ones, be subject to the elder. Yes, all of you clothe yourselves with humility and subject yourselves to one another; for “God resists the proud, but gives grace to the humble.”'),
  ('1 Peter', 5, 6, 'Humble yourselves therefore under the mighty hand of God, that he may exalt you in due time,'),
  ('1 Peter', 5, 7, 'casting all your worries on him, because he cares for you.'),
  ('1 Peter', 5, 8, 'Be sober and self-controlled. Be watchful. Your adversary, the devil, walks around like a roaring lion, seeking whom he may devour.'),
  ('1 Peter', 5, 9, 'Withstand him steadfast in your faith, knowing that your brothers who are in the world are undergoing the same sufferings.'),
  ('1 Peter', 5, 10, 'But may the God of all grace, who called you to his eternal glory by Christ Jesus, after you have suffered a little while, perfect, establish, strengthen, and settle you.'),
  ('1 Peter', 5, 11, 'To him be the glory and the power forever and ever. Amen.'),
  ('1 Peter', 5, 12, 'Through Silvanus, our faithful brother, as I consider him, I have written to you briefly, exhorting and testifying that this is the true grace of God in which you stand.'),
  ('1 Peter', 5, 13, 'She who is in Babylon, chosen together with you, greets you. So does Mark, my son.'),
  ('1 Peter', 5, 14, 'Greet one another with a kiss of love. Peace be to all of you who are in Christ Jesus. Amen.'),
  ('2 Peter', 1, 1, 'Simon Peter, a servant and apostle of Jesus Christ, to those who have obtained a like precious faith with us in the righteousness of our God and Savior, Jesus Christ:'),
  ('2 Peter', 1, 2, 'Grace to you and peace be multiplied in the knowledge of God and of Jesus our Lord,'),
  ('2 Peter', 1, 3, 'seeing that his divine power has granted to us all things that pertain to life and godliness, through the knowledge of him who called us by his own glory and virtue,'),
  ('2 Peter', 1, 4, 'by which he has granted to us his precious and exceedingly great promises; that through these you may become partakers of the divine nature, having escaped from the corruption that is in the world by lust.'),
  ('2 Peter', 1, 5, 'Yes, and for this very cause adding on your part all diligence, in your faith supply moral excellence; and in moral excellence, knowledge;'),
  ('2 Peter', 1, 6, 'and in knowledge, self-control; and in self-control, perseverance; and in perseverance, godliness;'),
  ('2 Peter', 1, 7, 'and in godliness, brotherly affection; and in brotherly affection, love.'),
  ('2 Peter', 1, 8, 'For if these things are yours and abound, they make you to not be idle or unfruitful in the knowledge of our Lord Jesus Christ.'),
  ('2 Peter', 1, 9, 'For he who lacks these things is blind, seeing only what is near, having forgotten the cleansing from his old sins.'),
  ('2 Peter', 1, 10, 'Therefore, brothers, be more diligent to make your calling and election sure. For if you do these things, you will never stumble.'),
  ('2 Peter', 1, 11, 'For thus you will be richly supplied with the entrance into the eternal Kingdom of our Lord and Savior, Jesus Christ.'),
  ('2 Peter', 1, 12, 'Therefore I will not be negligent to remind you of these things, though you know them and are established in the present truth.'),
  ('2 Peter', 1, 13, 'I think it right, as long as I am in this tent, to stir you up by reminding you,'),
  ('2 Peter', 1, 14, 'knowing that the putting off of my tent comes swiftly, even as our Lord Jesus Christ made clear to me.'),
  ('2 Peter', 1, 15, 'Yes, I will make every effort that you may always be able to remember these things even after my departure.'),
  ('2 Peter', 1, 16, 'For we didn’t follow cunningly devised fables when we made known to you the power and coming of our Lord Jesus Christ, but we were eyewitnesses of his majesty.'),
  ('2 Peter', 1, 17, 'For he received from God the Father honor and glory when the voice came to him from the Majestic Glory, “This is my beloved Son, in whom I am well pleased.”'),
  ('2 Peter', 1, 18, 'We heard this voice come out of heaven when we were with him on the holy mountain.'),
  ('2 Peter', 1, 19, 'We have the more sure word of prophecy; and you do well that you heed it as to a lamp shining in a dark place, until the day dawns and the morning star arises in your hearts,'),
  ('2 Peter', 1, 20, 'knowing this first, that no prophecy of Scripture is of private interpretation.'),
  ('2 Peter', 1, 21, 'For no prophecy ever came by the will of man, but holy men of God spoke, being moved by the Holy Spirit.'),
  ('2 Peter', 2, 1, 'But false prophets also arose among the people, as false teachers will also be among you, who will secretly bring in destructive heresies, denying even the Master who bought them, bringing on themselves swift destruction.'),
  ('2 Peter', 2, 2, 'Many will follow their immoral ways, and as a result, the way of the truth will be maligned.'),
  ('2 Peter', 2, 3, 'In covetousness they will exploit you with deceptive words: whose sentence now from of old doesn’t linger, and their destruction will not slumber.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('2 Peter', 2, 4, 'For if God didn’t spare angels when they sinned, but cast them down to Tartarus, and committed them to pits of darkness to be reserved for judgment;'),
  ('2 Peter', 2, 5, 'and didn’t spare the ancient world, but preserved Noah with seven others, a preacher of righteousness, when he brought a flood on the world of the ungodly,'),
  ('2 Peter', 2, 6, 'and turning the cities of Sodom and Gomorrah into ashes, condemned them to destruction, having made them an example to those who would live in an ungodly way,'),
  ('2 Peter', 2, 7, 'and delivered righteous Lot, who was very distressed by the lustful life of the wicked'),
  ('2 Peter', 2, 8, '(for that righteous man dwelling among them was tormented in his righteous soul from day to day with seeing and hearing lawless deeds),'),
  ('2 Peter', 2, 9, 'then the Lord knows how to deliver the godly out of temptation and to keep the unrighteous under punishment for the day of judgment,'),
  ('2 Peter', 2, 10, 'but chiefly those who walk after the flesh in the lust of defilement and despise authority. Daring, self-willed, they are not afraid to speak evil of dignitaries,'),
  ('2 Peter', 2, 11, 'whereas angels, though greater in might and power, don’t bring a slanderous judgment against them before the Lord.'),
  ('2 Peter', 2, 12, 'But these, as unreasoning creatures, born natural animals to be taken and destroyed, speaking evil in matters about which they are ignorant, will in their destroying surely be destroyed,'),
  ('2 Peter', 2, 13, 'receiving the wages of unrighteousness; people who count it pleasure to revel in the daytime, spots and defects, reveling in their deceit while they feast with you;'),
  ('2 Peter', 2, 14, 'having eyes full of adultery, and who can’t cease from sin, enticing unsettled souls, having a heart trained in greed, accursed children!'),
  ('2 Peter', 2, 15, 'Forsaking the right way, they went astray, having followed the way of Balaam the son of Beor, who loved the wages of wrongdoing;'),
  ('2 Peter', 2, 16, 'but he was rebuked for his own disobedience. A speechless donkey spoke with a man’s voice and stopped the madness of the prophet.'),
  ('2 Peter', 2, 17, 'These are wells without water, clouds driven by a storm, for whom the blackness of darkness has been reserved forever.'),
  ('2 Peter', 2, 18, 'For, uttering great swelling words of emptiness, they entice in the lusts of the flesh, by licentiousness, those who are indeed escaping from those who live in error;'),
  ('2 Peter', 2, 19, 'promising them liberty, while they themselves are bondservants of corruption; for a man is brought into bondage by whoever overcomes him.'),
  ('2 Peter', 2, 20, 'For if, after they have escaped the defilement of the world through the knowledge of the Lord and Savior Jesus Christ, they are again entangled in it and overcome, the last state has become worse for them than the first.'),
  ('2 Peter', 2, 21, 'For it would be better for them not to have known the way of righteousness, than after knowing it, to turn back from the holy commandment delivered to them.'),
  ('2 Peter', 2, 22, 'But it has happened to them according to the true proverb, “The dog turns to his own vomit again,” and “the sow that has washed to wallowing in the mire.”'),
  ('2 Peter', 3, 1, 'This is now, beloved, the second letter that I have written to you; and in both of them I stir up your sincere mind by reminding you'),
  ('2 Peter', 3, 2, 'that you should remember the words which were spoken before by the holy prophets and the commandment of us, the apostles of the Lord and Savior,'),
  ('2 Peter', 3, 3, 'knowing this first, that in the last days mockers will come, walking after their own lusts'),
  ('2 Peter', 3, 4, 'and saying, “Where is the promise of his coming? For, from the day that the fathers fell asleep, all things continue as they were from the beginning of the creation.”'),
  ('2 Peter', 3, 5, 'For they willfully forget that there were heavens from of old, and an earth formed out of water and amid water by the word of God,'),
  ('2 Peter', 3, 6, 'by which means the world that existed then, being overflowed with water, perished.'),
  ('2 Peter', 3, 7, 'But the heavens that exist now and the earth, by the same word have been stored up for fire, being reserved against the day of judgment and destruction of ungodly men.'),
  ('2 Peter', 3, 8, 'But don’t forget this one thing, beloved, that one day is with the Lord as a thousand years, and a thousand years as one day.'),
  ('2 Peter', 3, 9, 'The Lord is not slow concerning his promise, as some count slowness; but he is patient with us, not wishing that anyone should perish, but that all should come to repentance.'),
  ('2 Peter', 3, 10, 'But the day of the Lord will come as a thief in the night, in which the heavens will pass away with a great noise, and the elements will be dissolved with fervent heat; and the earth and the works that are in it will be burned up.'),
  ('2 Peter', 3, 11, 'Therefore, since all these things will be destroyed like this, what kind of people ought you to be in holy living and godliness,'),
  ('2 Peter', 3, 12, 'looking for and earnestly desiring the coming of the day of God, which will cause the burning heavens to be dissolved, and the elements will melt with fervent heat?'),
  ('2 Peter', 3, 13, 'But, according to his promise, we look for new heavens and a new earth, in which righteousness dwells.'),
  ('2 Peter', 3, 14, 'Therefore, beloved, seeing that you look for these things, be diligent to be found in peace, without defect and blameless in his sight.'),
  ('2 Peter', 3, 15, 'Regard the patience of our Lord as salvation; even as our beloved brother Paul also, according to the wisdom given to him, wrote to you,'),
  ('2 Peter', 3, 16, 'as also in all of his letters, speaking in them of these things. In those, there are some things that are hard to understand, which the ignorant and unsettled twist, as they also do to the other Scriptures, to their own destruction.'),
  ('2 Peter', 3, 17, 'You therefore, beloved, knowing these things beforehand, beware, lest being carried away with the error of the wicked, you fall from your own steadfastness.'),
  ('2 Peter', 3, 18, 'But grow in the grace and knowledge of our Lord and Savior Jesus Christ. To him be the glory both now and forever. Amen.'),
  ('1 John', 1, 1, 'That which was from the beginning, that which we have heard, that which we have seen with our eyes, that which we saw, and our hands touched, concerning the Word of life'),
  ('1 John', 1, 2, '(and the life was revealed, and we have seen, and testify, and declare to you the life, the eternal life, which was with the Father, and was revealed to us);'),
  ('1 John', 1, 3, 'that which we have seen and heard we declare to you, that you also may have fellowship with us. Yes, and our fellowship is with the Father and with his Son, Jesus Christ.'),
  ('1 John', 1, 4, 'And we write these things to you, that our joy may be fulfilled.'),
  ('1 John', 1, 5, 'This is the message which we have heard from him and announce to you, that God is light, and in him is no darkness at all.'),
  ('1 John', 1, 6, 'If we say that we have fellowship with him and walk in the darkness, we lie and don’t tell the truth.'),
  ('1 John', 1, 7, 'But if we walk in the light as he is in the light, we have fellowship with one another, and the blood of Jesus Christ his Son cleanses us from all sin.'),
  ('1 John', 1, 8, 'If we say that we have no sin, we deceive ourselves, and the truth is not in us.'),
  ('1 John', 1, 9, 'If we confess our sins, he is faithful and righteous to forgive us the sins and to cleanse us from all unrighteousness.'),
  ('1 John', 1, 10, 'If we say that we haven’t sinned, we make him a liar, and his word is not in us.'),
  ('1 John', 2, 1, 'My little children, I write these things to you so that you may not sin. If anyone sins, we have a Counselor with the Father, Jesus Christ, the righteous.'),
  ('1 John', 2, 2, 'And he is the atoning sacrifice for our sins, and not for ours only, but also for the whole world.'),
  ('1 John', 2, 3, 'This is how we know that we know him: if we keep his commandments.'),
  ('1 John', 2, 4, 'One who says, “I know him,” and doesn’t keep his commandments, is a liar, and the truth isn’t in him.'),
  ('1 John', 2, 5, 'But God’s love has most certainly been perfected in whoever keeps his word. This is how we know that we are in him:'),
  ('1 John', 2, 6, 'he who says he remains in him ought himself also to walk just like he walked.'),
  ('1 John', 2, 7, 'Brothers, I write no new commandment to you, but an old commandment which you had from the beginning. The old commandment is the word which you heard from the beginning.'),
  ('1 John', 2, 8, 'Again, I write a new commandment to you, which is true in him and in you, because the darkness is passing away and the true light already shines.'),
  ('1 John', 2, 9, 'He who says he is in the light and hates his brother is in the darkness even until now.'),
  ('1 John', 2, 10, 'He who loves his brother remains in the light, and there is no occasion for stumbling in him.'),
  ('1 John', 2, 11, 'But he who hates his brother is in the darkness, and walks in the darkness, and doesn’t know where he is going, because the darkness has blinded his eyes.'),
  ('1 John', 2, 12, 'I write to you, little children, because your sins are forgiven you for his name’s sake.'),
  ('1 John', 2, 13, 'I write to you, fathers, because you know him who is from the beginning. I write to you, young men, because you have overcome the evil one. I write to you, little children, because you know the Father.'),
  ('1 John', 2, 14, 'I have written to you, fathers, because you know him who is from the beginning. I have written to you, young men, because you are strong, and the word of God remains in you, and you have overcome the evil one.'),
  ('1 John', 2, 15, 'Don’t love the world or the things that are in the world. If anyone loves the world, the Father’s love isn’t in him.'),
  ('1 John', 2, 16, 'For all that is in the world—the lust of the flesh, the lust of the eyes, and the pride of life—isn’t the Father’s, but is the world’s.'),
  ('1 John', 2, 17, 'The world is passing away with its lusts, but he who does God’s will remains forever.'),
  ('1 John', 2, 18, 'Little children, these are the end times, and as you heard that the Antichrist is coming, even now many antichrists have arisen. By this we know that it is the final hour.'),
  ('1 John', 2, 19, 'They went out from us, but they didn’t belong to us; for if they had belonged to us, they would have continued with us. But they left, that they might be revealed that none of them belong to us.'),
  ('1 John', 2, 20, 'You have an anointing from the Holy One, and you all have knowledge.'),
  ('1 John', 2, 21, 'I have not written to you because you don’t know the truth, but because you know it, and because no lie is of the truth.'),
  ('1 John', 2, 22, 'Who is the liar but he who denies that Jesus is the Christ? This is the Antichrist, he who denies the Father and the Son.'),
  ('1 John', 2, 23, 'Whoever denies the Son doesn’t have the Father. He who confesses the Son has the Father also.'),
  ('1 John', 2, 24, 'Therefore, as for you, let that remain in you which you heard from the beginning. If that which you heard from the beginning remains in you, you also will remain in the Son, and in the Father.'),
  ('1 John', 2, 25, 'This is the promise which he promised us, the eternal life.'),
  ('1 John', 2, 26, 'These things I have written to you concerning those who would lead you astray.'),
  ('1 John', 2, 27, 'As for you, the anointing which you received from him remains in you, and you don’t need for anyone to teach you. But as his anointing teaches you concerning all things, and is true, and is no lie, and even as it taught you, you will remain in him.'),
  ('1 John', 2, 28, 'Now, little children, remain in him, that when he appears, we may have boldness and not be ashamed before him at his coming.'),
  ('1 John', 2, 29, 'If you know that he is righteous, you know that everyone who practices righteousness has been born of him.'),
  ('1 John', 3, 1, 'See how great a love the Father has given to us, that we should be called children of God! For this cause the world doesn’t know us, because it didn’t know him.'),
  ('1 John', 3, 2, 'Beloved, now we are children of God. It is not yet revealed what we will be; but we know that when he is revealed, we will be like him, for we will see him just as he is.'),
  ('1 John', 3, 3, 'Everyone who has this hope set on him purifies himself, even as he is pure.'),
  ('1 John', 3, 4, 'Everyone who sins also commits lawlessness. Sin is lawlessness.'),
  ('1 John', 3, 5, 'You know that he was revealed to take away our sins, and no sin is in him.'),
  ('1 John', 3, 6, 'Whoever remains in him doesn’t sin. Whoever sins hasn’t seen him and doesn’t know him.'),
  ('1 John', 3, 7, 'Little children, let no one lead you astray. He who does righteousness is righteous, even as he is righteous.'),
  ('1 John', 3, 8, 'He who sins is of the devil, for the devil has been sinning from the beginning. To this end the Son of God was revealed: that he might destroy the works of the devil.'),
  ('1 John', 3, 9, 'Whoever is born of God doesn’t commit sin, because his seed remains in him, and he can’t sin, because he is born of God.'),
  ('1 John', 3, 10, 'In this the children of God are revealed, and the children of the devil. Whoever doesn’t do righteousness is not of God, neither is he who doesn’t love his brother.'),
  ('1 John', 3, 11, 'For this is the message which you heard from the beginning, that we should love one another—'),
  ('1 John', 3, 12, 'unlike Cain, who was of the evil one and killed his brother. Why did he kill him? Because his deeds were evil, and his brother’s righteous.'),
  ('1 John', 3, 13, 'Don’t be surprised, my brothers, if the world hates you.'),
  ('1 John', 3, 14, 'We know that we have passed out of death into life, because we love the brothers. He who doesn’t love his brother remains in death.'),
  ('1 John', 3, 15, 'Whoever hates his brother is a murderer, and you know that no murderer has eternal life remaining in him.'),
  ('1 John', 3, 16, 'By this we know love, because he laid down his life for us. And we ought to lay down our lives for the brothers.'),
  ('1 John', 3, 17, 'But whoever has the world’s goods and sees his brother in need, then closes his heart of compassion against him, how does God’s love remain in him?'),
  ('1 John', 3, 18, 'My little children, let’s not love in word only, or with the tongue only, but in deed and truth.'),
  ('1 John', 3, 19, 'And by this we know that we are of the truth and persuade our hearts before him,'),
  ('1 John', 3, 20, 'because if our heart condemns us, God is greater than our heart, and knows all things.'),
  ('1 John', 3, 21, 'Beloved, if our hearts don’t condemn us, we have boldness toward God;'),
  ('1 John', 3, 22, 'so whatever we ask, we receive from him, because we keep his commandments and do the things that are pleasing in his sight.'),
  ('1 John', 3, 23, 'This is his commandment, that we should believe in the name of his Son, Jesus Christ, and love one another, even as he commanded.'),
  ('1 John', 3, 24, 'He who keeps his commandments remains in him, and he in him. By this we know that he remains in us, by the Spirit which he gave us.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('1 John', 4, 1, 'Beloved, don’t believe every spirit, but test the spirits, whether they are of God, because many false prophets have gone out into the world.'),
  ('1 John', 4, 2, 'By this you know the Spirit of God: every spirit who confesses that Jesus Christ has come in the flesh is of God,'),
  ('1 John', 4, 3, 'and every spirit who doesn’t confess that Jesus Christ has come in the flesh is not of God; and this is the spirit of the Antichrist, of whom you have heard that it comes. Now it is in the world already.'),
  ('1 John', 4, 4, 'You are of God, little children, and have overcome them, because greater is he who is in you than he who is in the world.'),
  ('1 John', 4, 5, 'They are of the world. Therefore they speak of the world, and the world hears them.'),
  ('1 John', 4, 6, 'We are of God. He who knows God listens to us. He who is not of God doesn’t listen to us. By this we know the spirit of truth, and the spirit of error.'),
  ('1 John', 4, 7, 'Beloved, let’s love one another, for love is of God; and everyone who loves has been born of God and knows God.'),
  ('1 John', 4, 8, 'He who doesn’t love doesn’t know God, for God is love.'),
  ('1 John', 4, 9, 'By this God’s love was revealed in us, that God has sent his only born Son into the world that we might live through him.'),
  ('1 John', 4, 10, 'In this is love, not that we loved God, but that he loved us, and sent his Son as the atoning sacrifice for our sins.'),
  ('1 John', 4, 11, 'Beloved, if God loved us in this way, we also ought to love one another.'),
  ('1 John', 4, 12, 'No one has seen God at any time. If we love one another, God remains in us, and his love has been perfected in us.'),
  ('1 John', 4, 13, 'By this we know that we remain in him and he in us, because he has given us of his Spirit.'),
  ('1 John', 4, 14, 'We have seen and testify that the Father has sent the Son as the Savior of the world.'),
  ('1 John', 4, 15, 'Whoever confesses that Jesus is the Son of God, God remains in him, and he in God.'),
  ('1 John', 4, 16, 'We know and have believed the love which God has for us. God is love, and he who remains in love remains in God, and God remains in him.'),
  ('1 John', 4, 17, 'In this, love has been made perfect among us, that we may have boldness in the day of judgment, because as he is, even so we are in this world.'),
  ('1 John', 4, 18, 'There is no fear in love; but perfect love casts out fear, because fear has punishment. He who fears is not made perfect in love.'),
  ('1 John', 4, 19, 'We love him, because he first loved us.'),
  ('1 John', 4, 20, 'If a man says, “I love God,” and hates his brother, he is a liar; for he who doesn’t love his brother whom he has seen, how can he love God whom he has not seen?'),
  ('1 John', 4, 21, 'This commandment we have from him, that he who loves God should also love his brother.'),
  ('1 John', 5, 1, 'Whoever believes that Jesus is the Christ has been born of God. Whoever loves the Father also loves the child who is born of him.'),
  ('1 John', 5, 2, 'By this we know that we love the children of God, when we love God and keep his commandments.'),
  ('1 John', 5, 3, 'For this is loving God, that we keep his commandments. His commandments are not grievous.'),
  ('1 John', 5, 4, 'For whatever is born of God overcomes the world. This is the victory that has overcome the world: your faith.'),
  ('1 John', 5, 5, 'Who is he who overcomes the world, but he who believes that Jesus is the Son of God?'),
  ('1 John', 5, 6, 'This is he who came by water and blood, Jesus Christ; not with the water only, but with the water and the blood. It is the Spirit who testifies, because the Spirit is the truth.'),
  ('1 John', 5, 7, 'For there are three who testify:'),
  ('1 John', 5, 8, 'the Spirit, the water, and the blood; and the three agree as one.'),
  ('1 John', 5, 9, 'If we receive the witness of men, the witness of God is greater; for this is God’s testimony which he has testified concerning his Son.'),
  ('1 John', 5, 10, 'He who believes in the Son of God has the testimony in himself. He who doesn’t believe God has made him a liar, because he has not believed in the testimony that God has given concerning his Son.'),
  ('1 John', 5, 11, 'The testimony is this: that God gave to us eternal life, and this life is in his Son.'),
  ('1 John', 5, 12, 'He who has the Son has the life. He who doesn’t have God’s Son doesn’t have the life.'),
  ('1 John', 5, 13, 'These things I have written to you who believe in the name of the Son of God, that you may know that you have eternal life, and that you may continue to believe in the name of the Son of God.'),
  ('1 John', 5, 14, 'This is the boldness which we have toward him, that if we ask anything according to his will, he listens to us.'),
  ('1 John', 5, 15, 'And if we know that he listens to us, whatever we ask, we know that we have the petitions which we have asked of him.'),
  ('1 John', 5, 16, 'If anyone sees his brother sinning a sin not leading to death, he shall ask, and God will give him life for those who sin not leading to death. There is sin leading to death. I don’t say that he should make a request concerning this.'),
  ('1 John', 5, 17, 'All unrighteousness is sin, and there is sin not leading to death.'),
  ('1 John', 5, 18, 'We know that whoever is born of God doesn’t sin, but he who was born of God keeps himself, and the evil one doesn’t touch him.'),
  ('1 John', 5, 19, 'We know that we are of God, and the whole world lies in the power of the evil one.'),
  ('1 John', 5, 20, 'We know that the Son of God has come and has given us an understanding, that we know him who is true; and we are in him who is true, in his Son Jesus Christ. This is the true God and eternal life.'),
  ('1 John', 5, 21, 'Little children, keep yourselves from idols.'),
  ('2 John', 1, 1, 'The elder, to the chosen lady and her children, whom I love in truth, and not I only, but also all those who know the truth,'),
  ('2 John', 1, 2, 'for the truth’s sake, which remains in us, and it will be with us forever:'),
  ('2 John', 1, 3, 'Grace, mercy, and peace will be with us, from God the Father and from the Lord Jesus Christ, the Son of the Father, in truth and love.'),
  ('2 John', 1, 4, 'I rejoice greatly that I have found some of your children walking in truth, even as we have been commanded by the Father.'),
  ('2 John', 1, 5, 'Now I beg you, dear lady, not as though I wrote to you a new commandment, but that which we had from the beginning, that we love one another.'),
  ('2 John', 1, 6, 'This is love, that we should walk according to his commandments. This is the commandment, even as you heard from the beginning, that you should walk in it.'),
  ('2 John', 1, 7, 'For many deceivers have gone out into the world, those who don’t confess that Jesus Christ came in the flesh. This is the deceiver and the Antichrist.'),
  ('2 John', 1, 8, 'Watch yourselves, that we don’t lose the things which we have accomplished, but that we receive a full reward.'),
  ('2 John', 1, 9, 'Whoever transgresses and doesn’t remain in the teaching of Christ doesn’t have God. He who remains in the teaching has both the Father and the Son.'),
  ('2 John', 1, 10, 'If anyone comes to you and doesn’t bring this teaching, don’t receive him into your house, and don’t welcome him,'),
  ('2 John', 1, 11, 'for he who welcomes him participates in his evil deeds.'),
  ('2 John', 1, 12, 'Having many things to write to you, I don’t want to do so with paper and ink, but I hope to come to you and to speak face to face, that our joy may be made full.'),
  ('2 John', 1, 13, 'The children of your chosen sister greet you. Amen.'),
  ('3 John', 1, 1, 'The elder to Gaius the beloved, whom I love in truth.'),
  ('3 John', 1, 2, 'Beloved, I pray that you may prosper in all things and be healthy, even as your soul prospers.'),
  ('3 John', 1, 3, 'For I rejoiced greatly when brothers came and testified about your truth, even as you walk in truth.'),
  ('3 John', 1, 4, 'I have no greater joy than this: to hear about my children walking in truth.'),
  ('3 John', 1, 5, 'Beloved, you do a faithful work in whatever you accomplish for those who are brothers and strangers.'),
  ('3 John', 1, 6, 'They have testified about your love before the assembly. You will do well to send them forward on their journey in a way worthy of God,'),
  ('3 John', 1, 7, 'because for the sake of the Name they went out, taking nothing from the Gentiles.'),
  ('3 John', 1, 8, 'We therefore ought to receive such, that we may be fellow workers for the truth.'),
  ('3 John', 1, 9, 'I wrote to the assembly, but Diotrephes, who loves to be first among them, doesn’t accept what we say.'),
  ('3 John', 1, 10, 'Therefore, if I come, I will call attention to his deeds which he does, unjustly accusing us with wicked words. Not content with this, he doesn’t receive the brothers himself, and those who would, he forbids and throws out of the assembly.'),
  ('3 John', 1, 11, 'Beloved, don’t imitate that which is evil, but that which is good. He who does good is of God. He who does evil hasn’t seen God.'),
  ('3 John', 1, 12, 'Demetrius has the testimony of all, and of the truth itself; yes, we also testify, and you know that our testimony is true.'),
  ('3 John', 1, 13, 'I had many things to write to you, but I am unwilling to write to you with ink and pen;'),
  ('3 John', 1, 14, 'but I hope to see you soon. Then we will speak face to face. Peace be to you. The friends greet you. Greet the friends by name.'),
  ('Jude', 1, 1, 'Jude, a servant of Jesus Christ, and brother of James, to those who are called, sanctified by God the Father, and kept for Jesus Christ:'),
  ('Jude', 1, 2, 'May mercy, peace, and love be multiplied to you.'),
  ('Jude', 1, 3, 'Beloved, while I was very eager to write to you about our common salvation, I was constrained to write to you exhorting you to contend earnestly for the faith which was once for all delivered to the saints.'),
  ('Jude', 1, 4, 'For there are certain men who crept in secretly, even those who were long ago written about for this condemnation: ungodly men, turning the grace of our God into indecency, and denying our only Master, God, and Lord, Jesus Christ.'),
  ('Jude', 1, 5, 'Now I desire to remind you, though you already know this, that the Lord, having saved a people out of the land of Egypt, afterward destroyed those who didn’t believe.'),
  ('Jude', 1, 6, 'Angels who didn’t keep their first domain, but deserted their own dwelling place, he has kept in everlasting bonds under darkness for the judgment of the great day.'),
  ('Jude', 1, 7, 'Even as Sodom and Gomorrah and the cities around them, having in the same way as these given themselves over to sexual immorality and gone after strange flesh, are shown as an example, suffering the punishment of eternal fire.'),
  ('Jude', 1, 8, 'Yet in the same way, these also in their dreaming defile the flesh, despise authority, and slander celestial beings.'),
  ('Jude', 1, 9, 'But Michael, the archangel, when contending with the devil and arguing about the body of Moses, dared not bring against him an abusive condemnation, but said, “May the Lord rebuke you!”'),
  ('Jude', 1, 10, 'But these speak evil of whatever things they don’t know. They are destroyed in these things that they understand naturally, like the creatures without reason.'),
  ('Jude', 1, 11, 'Woe to them! For they went in the way of Cain, and ran riotously in the error of Balaam for hire, and perished in Korah’s rebellion.'),
  ('Jude', 1, 12, 'These are hidden rocky reefs in your love feasts when they feast with you, shepherds who without fear feed themselves; clouds without water, carried along by winds; autumn trees without fruit, twice dead, plucked up by the roots;'),
  ('Jude', 1, 13, 'wild waves of the sea, foaming out their own shame; wandering stars, for whom the blackness of darkness has been reserved forever.'),
  ('Jude', 1, 14, 'About these also Enoch, the seventh from Adam, prophesied, saying, “Behold, the Lord came with ten thousands of his holy ones,'),
  ('Jude', 1, 15, 'to execute judgment on all, and to convict all the ungodly of all their works of ungodliness which they have done in an ungodly way, and of all the hard things which ungodly sinners have spoken against him.”'),
  ('Jude', 1, 16, 'These are murmurers and complainers, walking after their lusts—and their mouth speaks proud things—showing respect of persons to gain advantage.'),
  ('Jude', 1, 17, 'But you, beloved, remember the words which have been spoken before by the apostles of our Lord Jesus Christ.'),
  ('Jude', 1, 18, 'They said to you, “In the last time there will be mockers, walking after their own ungodly lusts.”'),
  ('Jude', 1, 19, 'These are those who cause divisions and are sensual, not having the Spirit.'),
  ('Jude', 1, 20, 'But you, beloved, keep building up yourselves on your most holy faith, praying in the Holy Spirit.'),
  ('Jude', 1, 21, 'Keep yourselves in God’s love, looking for the mercy of our Lord Jesus Christ to eternal life.'),
  ('Jude', 1, 22, 'On some have compassion, making a distinction,'),
  ('Jude', 1, 23, 'and some save, snatching them out of the fire with fear, hating even the clothing stained by the flesh.'),
  ('Jude', 1, 24, 'Now to him who is able to keep them from stumbling, and to present you faultless before the presence of his glory in great joy,'),
  ('Jude', 1, 25, 'to God our Savior, who alone is wise, be glory and majesty, dominion and power, both now and forever. Amen.'),
  ('Revelation', 1, 1, 'This is the Revelation of Jesus Christ, which God gave him to show to his servants the things which must happen soon, which he sent and made known by his angel to his servant, John,'),
  ('Revelation', 1, 2, 'who testified to God’s word and of the testimony of Jesus Christ, about everything that he saw.'),
  ('Revelation', 1, 3, 'Blessed is he who reads and those who hear the words of the prophecy, and keep the things that are written in it, for the time is near.'),
  ('Revelation', 1, 4, 'John, to the seven assemblies that are in Asia: Grace to you and peace from God, who is and who was and who is to come; and from the seven Spirits who are before his throne;'),
  ('Revelation', 1, 5, 'and from Jesus Christ, the faithful witness, the firstborn of the dead, and the ruler of the kings of the earth. To him who loves us, and washed us from our sins by his blood—'),
  ('Revelation', 1, 6, 'and he made us to be a Kingdom, priests to his God and Father—to him be the glory and the dominion forever and ever. Amen.');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Revelation', 1, 7, 'Behold, he is coming with the clouds, and every eye will see him, including those who pierced him. All the tribes of the earth will mourn over him. Even so, Amen.'),
  ('Revelation', 1, 8, '“I am the Alpha and the Omega,” says the Lord God, “who is and who was and who is to come, the Almighty.”'),
  ('Revelation', 1, 9, 'I John, your brother and partner with you in the oppression, Kingdom, and perseverance in Christ Jesus, was on the isle that is called Patmos because of God’s Word and the testimony of Jesus Christ.'),
  ('Revelation', 1, 10, 'I was in the Spirit on the Lord’s day, and I heard behind me a loud voice, like a trumpet'),
  ('Revelation', 1, 11, 'saying, “What you see, write in a book and send to the seven assemblies: to Ephesus, Smyrna, Pergamum, Thyatira, Sardis, Philadelphia, and to Laodicea.”'),
  ('Revelation', 1, 12, 'I turned to see the voice that spoke with me. Having turned, I saw seven golden lamp stands.'),
  ('Revelation', 1, 13, 'And among the lamp stands was one like a son of man, clothed with a robe reaching down to his feet, and with a golden sash around his chest.'),
  ('Revelation', 1, 14, 'His head and his hair were white as white wool, like snow. His eyes were like a flame of fire.'),
  ('Revelation', 1, 15, 'His feet were like burnished brass, as if it had been refined in a furnace. His voice was like the voice of many waters.'),
  ('Revelation', 1, 16, 'He had seven stars in his right hand. Out of his mouth proceeded a sharp two-edged sword. His face was like the sun shining at its brightest.'),
  ('Revelation', 1, 17, 'When I saw him, I fell at his feet like a dead man. He laid his right hand on me, saying, “Don’t be afraid. I am the first and the last,'),
  ('Revelation', 1, 18, 'and the Living one. I was dead, and behold, I am alive forever and ever. Amen. I have the keys of Death and of Hades.'),
  ('Revelation', 1, 19, 'Write therefore the things which you have seen, and the things which are, and the things which will happen hereafter.'),
  ('Revelation', 1, 20, 'The mystery of the seven stars which you saw in my right hand, and the seven golden lamp stands is this: The seven stars are the angels of the seven assemblies. The seven lamp stands are seven assemblies.'),
  ('Revelation', 2, 1, '“To the angel of the assembly in Ephesus write: “He who holds the seven stars in his right hand, he who walks among the seven golden lamp stands says these things:'),
  ('Revelation', 2, 2, '“I know your works, and your toil and perseverance, and that you can’t tolerate evil men, and have tested those who call themselves apostles, and they are not, and found them false.'),
  ('Revelation', 2, 3, 'You have perseverance and have endured for my name’s sake, and have not grown weary.'),
  ('Revelation', 2, 4, 'But I have this against you, that you left your first love.'),
  ('Revelation', 2, 5, 'Remember therefore from where you have fallen, and repent and do the first works; or else I am coming to you swiftly, and will move your lamp stand out of its place, unless you repent.'),
  ('Revelation', 2, 6, 'But this you have, that you hate the works of the Nicolaitans, which I also hate.'),
  ('Revelation', 2, 7, 'He who has an ear, let him hear what the Spirit says to the assemblies. To him who overcomes I will give to eat from the tree of life, which is in the Paradise of my God.'),
  ('Revelation', 2, 8, '“To the angel of the assembly in Smyrna write: “The first and the last, who was dead, and has come to life says these things:'),
  ('Revelation', 2, 9, '“I know your works, oppression, and your poverty (but you are rich), and the blasphemy of those who say they are Jews, and they are not, but are a synagogue of Satan.'),
  ('Revelation', 2, 10, 'Don’t be afraid of the things which you are about to suffer. Behold, the devil is about to throw some of you into prison, that you may be tested; and you will have oppression for ten days. Be faithful to death, and I will give you the crown of life.'),
  ('Revelation', 2, 11, 'He who has an ear, let him hear what the Spirit says to the assemblies. He who overcomes won’t be harmed by the second death.'),
  ('Revelation', 2, 12, '“To the angel of the assembly in Pergamum write: “He who has the sharp two-edged sword says these things:'),
  ('Revelation', 2, 13, '“I know your works and where you dwell, where Satan’s throne is. You hold firmly to my name, and didn’t deny my faith in the days of Antipas my witness, my faithful one, who was killed among you, where Satan dwells.'),
  ('Revelation', 2, 14, 'But I have a few things against you, because you have there some who hold the teaching of Balaam, who taught Balak to throw a stumbling block before the children of Israel, to eat things sacrificed to idols, and to commit sexual immorality.'),
  ('Revelation', 2, 15, 'So also you likewise have some who hold to the teaching of the Nicolaitans.'),
  ('Revelation', 2, 16, 'Repent therefore, or else I am coming to you quickly and I will make war against them with the sword of my mouth.'),
  ('Revelation', 2, 17, 'He who has an ear, let him hear what the Spirit says to the assemblies. To him who overcomes, to him I will give of the hidden manna, and I will give him a white stone, and on the stone a new name written which no one knows but he who receives it.'),
  ('Revelation', 2, 18, '“To the angel of the assembly in Thyatira write: “The Son of God, who has his eyes like a flame of fire, and his feet are like burnished brass, says these things:'),
  ('Revelation', 2, 19, '“I know your works, your love, faith, service, patient endurance, and that your last works are more than the first.'),
  ('Revelation', 2, 20, 'But I have this against you, that you tolerate your woman Jezebel, who calls herself a prophetess. She teaches and seduces my servants to commit sexual immorality and to eat things sacrificed to idols.'),
  ('Revelation', 2, 21, 'I gave her time to repent, but she refuses to repent of her sexual immorality.'),
  ('Revelation', 2, 22, 'Behold, I will throw her and those who commit adultery with her into a bed of great oppression, unless they repent of her works.'),
  ('Revelation', 2, 23, 'I will kill her children with Death, and all the assemblies will know that I am he who searches the minds and hearts. I will give to each one of you according to your deeds.'),
  ('Revelation', 2, 24, 'But to you I say, to the rest who are in Thyatira—as many as don’t have this teaching, who don’t know what some call ‘the deep things of Satan’—to you I say, I am not putting any other burden on you.'),
  ('Revelation', 2, 25, 'Nevertheless, hold that which you have firmly until I come.'),
  ('Revelation', 2, 26, 'He who overcomes, and he who keeps my works to the end, to him I will give authority over the nations.'),
  ('Revelation', 2, 27, 'He will rule them with a rod of iron, shattering them like clay pots, as I also have received of my Father;'),
  ('Revelation', 2, 28, 'and I will give him the morning star.'),
  ('Revelation', 2, 29, 'He who has an ear, let him hear what the Spirit says to the assemblies.'),
  ('Revelation', 3, 1, '“And to the angel of the assembly in Sardis write: “He who has the seven Spirits of God and the seven stars says these things: “I know your works, that you have a reputation of being alive, but you are dead.'),
  ('Revelation', 3, 2, 'Wake up and strengthen the things that remain, which you were about to throw away, for I have found no works of yours perfected before my God.'),
  ('Revelation', 3, 3, 'Remember therefore how you have received and heard. Keep it and repent. If therefore you won’t watch, I will come as a thief, and you won’t know what hour I will come upon you.'),
  ('Revelation', 3, 4, 'Nevertheless you have a few names in Sardis that didn’t defile their garments. They will walk with me in white, for they are worthy.'),
  ('Revelation', 3, 5, 'He who overcomes will be arrayed in white garments, and I will in no way blot his name out of the book of life, and I will confess his name before my Father, and before his angels.'),
  ('Revelation', 3, 6, 'He who has an ear, let him hear what the Spirit says to the assemblies.'),
  ('Revelation', 3, 7, '“To the angel of the assembly in Philadelphia write: “He who is holy, he who is true, he who has the key of David, he who opens and no one can shut, and who shuts and no one opens, says these things:'),
  ('Revelation', 3, 8, '“I know your works (behold, I have set before you an open door, which no one can shut), that you have a little power, and kept my word, and didn’t deny my name.'),
  ('Revelation', 3, 9, 'Behold, I make some of the synagogue of Satan, of those who say they are Jews, and they are not, but lie—behold, I will make them to come and worship before your feet, and to know that I have loved you.'),
  ('Revelation', 3, 10, 'Because you kept my command to endure, I also will keep you from the hour of testing which is to come on the whole world, to test those who dwell on the earth.'),
  ('Revelation', 3, 11, 'I am coming quickly! Hold firmly that which you have, so that no one takes your crown.'),
  ('Revelation', 3, 12, 'He who overcomes, I will make him a pillar in the temple of my God, and he will go out from there no more. I will write on him the name of my God and the name of the city of my God, the new Jerusalem, which comes down out of heaven from my God, and my own new name.'),
  ('Revelation', 3, 13, 'He who has an ear, let him hear what the Spirit says to the assemblies.'),
  ('Revelation', 3, 14, '“To the angel of the assembly in Laodicea write: “The Amen, the Faithful and True Witness, the Beginning of God’s creation, says these things:'),
  ('Revelation', 3, 15, '“I know your works, that you are neither cold nor hot. I wish you were cold or hot.'),
  ('Revelation', 3, 16, 'So, because you are lukewarm, and neither hot nor cold, I will vomit you out of my mouth.'),
  ('Revelation', 3, 17, 'Because you say, ‘I am rich, and have gotten riches, and have need of nothing,’ and don’t know that you are the wretched one, miserable, poor, blind, and naked;'),
  ('Revelation', 3, 18, 'I counsel you to buy from me gold refined by fire, that you may become rich; and white garments, that you may clothe yourself, and that the shame of your nakedness may not be revealed; and eye salve to anoint your eyes, that you may see.'),
  ('Revelation', 3, 19, 'As many as I love, I reprove and chasten. Be zealous therefore, and repent.'),
  ('Revelation', 3, 20, 'Behold, I stand at the door and knock. If anyone hears my voice and opens the door, then I will come in to him and will dine with him, and he with me.'),
  ('Revelation', 3, 21, 'He who overcomes, I will give to him to sit down with me on my throne, as I also overcame and sat down with my Father on his throne.'),
  ('Revelation', 3, 22, 'He who has an ear, let him hear what the Spirit says to the assemblies.”'),
  ('Revelation', 4, 1, 'After these things I looked and saw a door opened in heaven; and the first voice that I heard, like a trumpet speaking with me, was one saying, “Come up here, and I will show you the things which must happen after this.”'),
  ('Revelation', 4, 2, 'Immediately I was in the Spirit. Behold, there was a throne set in heaven, and one sitting on the throne'),
  ('Revelation', 4, 3, 'that looked like a jasper stone and a sardius. There was a rainbow around the throne, like an emerald to look at.'),
  ('Revelation', 4, 4, 'Around the throne were twenty-four thrones. On the thrones were twenty-four elders sitting, dressed in white garments, with crowns of gold on their heads.'),
  ('Revelation', 4, 5, 'Out of the throne proceed lightnings, sounds, and thunders. There were seven lamps of fire burning before his throne, which are the seven Spirits of God.'),
  ('Revelation', 4, 6, 'Before the throne was something like a sea of glass, similar to crystal. In the middle of the throne, and around the throne were four living creatures full of eyes before and behind.'),
  ('Revelation', 4, 7, 'The first creature was like a lion, the second creature like a calf, the third creature had a face like a man, and the fourth was like a flying eagle.'),
  ('Revelation', 4, 8, 'The four living creatures, each one of them having six wings, are full of eyes around and within. They have no rest day and night, saying, “Holy, holy, holy is the Lord God, the Almighty, who was and who is and who is to come!”'),
  ('Revelation', 4, 9, 'When the living creatures give glory, honor, and thanks to him who sits on the throne, to him who lives forever and ever,'),
  ('Revelation', 4, 10, 'the twenty-four elders fall down before him who sits on the throne and worship him who lives forever and ever, and throw their crowns before the throne, saying,'),
  ('Revelation', 4, 11, '“Worthy are you, our Lord and God, the Holy One, to receive the glory, the honor, and the power, for you created all things, and because of your desire they existed and were created!”'),
  ('Revelation', 5, 1, 'I saw, in the right hand of him who sat on the throne, a book written inside and outside, sealed shut with seven seals.'),
  ('Revelation', 5, 2, 'I saw a mighty angel proclaiming with a loud voice, “Who is worthy to open the book, and to break its seals?”'),
  ('Revelation', 5, 3, 'No one in heaven above, or on the earth, or under the earth, was able to open the book or to look in it.'),
  ('Revelation', 5, 4, 'Then I wept much, because no one was found worthy to open the book or to look in it.'),
  ('Revelation', 5, 5, 'One of the elders said to me, “Don’t weep. Behold, the Lion who is of the tribe of Judah, the Root of David, has overcome: he who opens the book and its seven seals.”'),
  ('Revelation', 5, 6, 'I saw in the middle of the throne and of the four living creatures, and in the middle of the elders, a Lamb standing, as though it had been slain, having seven horns and seven eyes, which are the seven Spirits of God, sent out into all the earth.'),
  ('Revelation', 5, 7, 'Then he came, and he took it out of the right hand of him who sat on the throne.'),
  ('Revelation', 5, 8, 'Now when he had taken the book, the four living creatures and the twenty-four elders fell down before the Lamb, each one having a harp, and golden bowls full of incense, which are the prayers of the saints.'),
  ('Revelation', 5, 9, 'They sang a new song, saying, “You are worthy to take the book and to open its seals, for you were killed, and bought us for God with your blood out of every tribe, language, people, and nation,'),
  ('Revelation', 5, 10, 'and made us kings and priests to our God; and we will reign on the earth.”'),
  ('Revelation', 5, 11, 'I looked, and I heard something like a voice of many angels around the throne, the living creatures, and the elders. The number of them was ten thousands of ten thousands, and thousands of thousands,'),
  ('Revelation', 5, 12, 'saying with a loud voice, “Worthy is the Lamb who has been killed to receive the power, wealth, wisdom, strength, honor, glory, and blessing!”'),
  ('Revelation', 5, 13, 'I heard every created thing which is in heaven, on the earth, under the earth, on the sea, and everything in them, saying, “To him who sits on the throne and to the Lamb be the blessing, the honor, the glory, and the dominion, forever and ever! Amen!”'),
  ('Revelation', 5, 14, 'The four living creatures said, “Amen!” Then the elders fell down and worshiped.'),
  ('Revelation', 6, 1, 'I saw that the Lamb opened one of the seven seals, and I heard one of the four living creatures saying, as with a voice of thunder, “Come and see!”'),
  ('Revelation', 6, 2, 'Then a white horse appeared, and he who sat on it had a bow. A crown was given to him, and he came out conquering, and to conquer.'),
  ('Revelation', 6, 3, 'When he opened the second seal, I heard the second living creature saying, “Come!”'),
  ('Revelation', 6, 4, 'Another came out, a red horse. To him who sat on it was given power to take peace from the earth, and that they should kill one another. There was given to him a great sword.'),
  ('Revelation', 6, 5, 'When he opened the third seal, I heard the third living creature saying, “Come and see!” And behold, a black horse, and he who sat on it had a balance in his hand.'),
  ('Revelation', 6, 6, 'I heard a voice in the middle of the four living creatures saying, “A choenix of wheat for a denarius, and three choenix of barley for a denarius! Don’t damage the oil and the wine!”'),
  ('Revelation', 6, 7, 'When he opened the fourth seal, I heard the fourth living creature saying, “Come and see!”'),
  ('Revelation', 6, 8, 'And behold, a pale horse, and the name of he who sat on it was Death. Hades followed with him. Authority over one fourth of the earth, to kill with the sword, with famine, with death, and by the wild animals of the earth was given to him.'),
  ('Revelation', 6, 9, 'When he opened the fifth seal, I saw underneath the altar the souls of those who had been killed for the Word of God, and for the testimony of the Lamb which they had.'),
  ('Revelation', 6, 10, 'They cried with a loud voice, saying, “How long, Master, the holy and true, until you judge and avenge our blood on those who dwell on the earth?”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Revelation', 6, 11, 'A long white robe was given to each of them. They were told that they should rest yet for a while, until their fellow servants and their brothers, who would also be killed even as they were, should complete their course.'),
  ('Revelation', 6, 12, 'I saw when he opened the sixth seal, and there was a great earthquake. The sun became black as sackcloth made of hair, and the whole moon became as blood.'),
  ('Revelation', 6, 13, 'The stars of the sky fell to the earth, like a fig tree dropping its unripe figs when it is shaken by a great wind.'),
  ('Revelation', 6, 14, 'The sky was removed like a scroll when it is rolled up. Every mountain and island was moved out of its place.'),
  ('Revelation', 6, 15, 'The kings of the earth, the princes, the commanding officers, the rich, the strong, and every slave and free person, hid themselves in the caves and in the rocks of the mountains.'),
  ('Revelation', 6, 16, 'They told the mountains and the rocks, “Fall on us, and hide us from the face of him who sits on the throne, and from the wrath of the Lamb,'),
  ('Revelation', 6, 17, 'for the great day of his wrath has come, and who is able to stand?”'),
  ('Revelation', 7, 1, 'After this, I saw four angels standing at the four corners of the earth, holding the four winds of the earth, so that no wind would blow on the earth, or on the sea, or on any tree.'),
  ('Revelation', 7, 2, 'I saw another angel ascend from the sunrise, having the seal of the living God. He cried with a loud voice to the four angels to whom it was given to harm the earth and the sea,'),
  ('Revelation', 7, 3, 'saying, “Don’t harm the earth, the sea, or the trees, until we have sealed the bondservants of our God on their foreheads!”'),
  ('Revelation', 7, 4, 'I heard the number of those who were sealed, one hundred forty-four thousand, sealed out of every tribe of the children of Israel:'),
  ('Revelation', 7, 5, 'of the tribe of Judah twelve thousand were sealed, of the tribe of Reuben twelve thousand, of the tribe of Gad twelve thousand,'),
  ('Revelation', 7, 6, 'of the tribe of Asher twelve thousand, of the tribe of Naphtali twelve thousand, of the tribe of Manasseh twelve thousand,'),
  ('Revelation', 7, 7, 'of the tribe of Simeon twelve thousand, of the tribe of Levi twelve thousand, of the tribe of Issachar twelve thousand,'),
  ('Revelation', 7, 8, 'of the tribe of Zebulun twelve thousand, of the tribe of Joseph twelve thousand, and of the tribe of Benjamin twelve thousand were sealed.'),
  ('Revelation', 7, 9, 'After these things I looked, and behold, a great multitude which no man could count, out of every nation and of all tribes, peoples, and languages, standing before the throne and before the Lamb, dressed in white robes, with palm branches in their hands.'),
  ('Revelation', 7, 10, 'They cried with a loud voice, saying, “Salvation be to our God, who sits on the throne, and to the Lamb!”'),
  ('Revelation', 7, 11, 'All the angels were standing around the throne, the elders, and the four living creatures; and they fell on their faces before his throne, and worshiped God,'),
  ('Revelation', 7, 12, 'saying, “Amen! Blessing, glory, wisdom, thanksgiving, honor, power, and might, be to our God forever and ever! Amen.”'),
  ('Revelation', 7, 13, 'One of the elders answered, saying to me, “These who are arrayed in the white robes, who are they, and where did they come from?”'),
  ('Revelation', 7, 14, 'I told him, “My lord, you know.” He said to me, “These are those who came out of the great suffering. They washed their robes and made them white in the Lamb’s blood.'),
  ('Revelation', 7, 15, 'Therefore they are before the throne of God, and they serve him day and night in his temple. He who sits on the throne will spread his tabernacle over them.'),
  ('Revelation', 7, 16, 'They will never be hungry or thirsty any more. The sun won’t beat on them, nor any heat;'),
  ('Revelation', 7, 17, 'for the Lamb who is in the middle of the throne shepherds them and leads them to springs of life-giving waters. And God will wipe away every tear from their eyes.”'),
  ('Revelation', 8, 1, 'When he opened the seventh seal, there was silence in heaven for about half an hour.'),
  ('Revelation', 8, 2, 'I saw the seven angels who stand before God, and seven trumpets were given to them.'),
  ('Revelation', 8, 3, 'Another angel came and stood over the altar, having a golden censer. Much incense was given to him, that he should add it to the prayers of all the saints on the golden altar which was before the throne.'),
  ('Revelation', 8, 4, 'The smoke of the incense, with the prayers of the saints, went up before God out of the angel’s hand.'),
  ('Revelation', 8, 5, 'The angel took the censer, and he filled it with the fire of the altar, then threw it on the earth. Thunders, sounds, lightnings, and an earthquake followed.'),
  ('Revelation', 8, 6, 'The seven angels who had the seven trumpets prepared themselves to sound.'),
  ('Revelation', 8, 7, 'The first sounded, and there followed hail and fire, mixed with blood, and they were thrown to the earth. One third of the earth was burned up, and one third of the trees were burned up, and all green grass was burned up.'),
  ('Revelation', 8, 8, 'The second angel sounded, and something like a great burning mountain was thrown into the sea. One third of the sea became blood,'),
  ('Revelation', 8, 9, 'and one third of the living creatures which were in the sea died. One third of the ships were destroyed.'),
  ('Revelation', 8, 10, 'The third angel sounded, and a great star fell from the sky, burning like a torch, and it fell on one third of the rivers, and on the springs of water.'),
  ('Revelation', 8, 11, 'The name of the star is “Wormwood.” One third of the waters became wormwood. Many people died from the waters, because they were made bitter.'),
  ('Revelation', 8, 12, 'The fourth angel sounded, and one third of the sun was struck, and one third of the moon, and one third of the stars, so that one third of them would be darkened; and the day wouldn’t shine for one third of it, and the night in the same way.'),
  ('Revelation', 8, 13, 'I saw, and I heard an eagle, flying in mid heaven, saying with a loud voice, “Woe! Woe! Woe to those who dwell on the earth, because of the other blasts of the trumpets of the three angels, who are yet to sound!”'),
  ('Revelation', 9, 1, 'The fifth angel sounded, and I saw a star from the sky which had fallen to the earth. The key to the pit of the abyss was given to him.'),
  ('Revelation', 9, 2, 'He opened the pit of the abyss, and smoke went up out of the pit, like the smoke from a burning furnace. The sun and the air were darkened because of the smoke from the pit.'),
  ('Revelation', 9, 3, 'Then out of the smoke came locusts on the earth, and power was given to them, as the scorpions of the earth have power.'),
  ('Revelation', 9, 4, 'They were told that they should not hurt the grass of the earth, neither any green thing, neither any tree, but only those people who don’t have God’s seal on their foreheads.'),
  ('Revelation', 9, 5, 'They were given power, not to kill them, but to torment them for five months. Their torment was like the torment of a scorpion when it strikes a person.'),
  ('Revelation', 9, 6, 'In those days people will seek death, and will in no way find it. They will desire to die, and death will flee from them.'),
  ('Revelation', 9, 7, 'The shapes of the locusts were like horses prepared for war. On their heads were something like golden crowns, and their faces were like people’s faces.'),
  ('Revelation', 9, 8, 'They had hair like women’s hair, and their teeth were like those of lions.'),
  ('Revelation', 9, 9, 'They had breastplates like breastplates of iron. The sound of their wings was like the sound of many chariots and horses rushing to war.'),
  ('Revelation', 9, 10, 'They have tails like those of scorpions, with stingers. In their tails they have power to harm men for five months.'),
  ('Revelation', 9, 11, 'They have over them as king the angel of the abyss. His name in Hebrew is “Abaddon”, but in Greek, he has the name “Apollyon”.'),
  ('Revelation', 9, 12, 'The first woe is past. Behold, there are still two woes coming after this.'),
  ('Revelation', 9, 13, 'The sixth angel sounded. I heard a voice from the horns of the golden altar which is before God,'),
  ('Revelation', 9, 14, 'saying to the sixth angel who had the trumpet, “Free the four angels who are bound at the great river Euphrates!”'),
  ('Revelation', 9, 15, 'The four angels were freed who had been prepared for that hour and day and month and year, so that they might kill one third of mankind.'),
  ('Revelation', 9, 16, 'The number of the armies of the horsemen was two hundred million. I heard the number of them.'),
  ('Revelation', 9, 17, 'Thus I saw the horses in the vision and those who sat on them, having breastplates of fiery red, hyacinth blue, and sulfur yellow; and the horses’ heads resembled lions’ heads. Out of their mouths proceed fire, smoke, and sulfur.'),
  ('Revelation', 9, 18, 'By these three plagues, one third of mankind was killed: by the fire, the smoke, and the sulfur, which proceeded out of their mouths.'),
  ('Revelation', 9, 19, 'For the power of the horses is in their mouths and in their tails. For their tails are like serpents, and have heads; and with them they harm.'),
  ('Revelation', 9, 20, 'The rest of mankind, who were not killed with these plagues, didn’t repent of the works of their hands, that they wouldn’t worship demons, and the idols of gold, and of silver, and of brass, and of stone, and of wood, which can’t see, hear, or walk.'),
  ('Revelation', 9, 21, 'They didn’t repent of their murders, their sorceries, their sexual immorality, or their thefts.'),
  ('Revelation', 10, 1, 'I saw a mighty angel coming down out of the sky, clothed with a cloud. A rainbow was on his head. His face was like the sun, and his feet like pillars of fire.'),
  ('Revelation', 10, 2, 'He had in his hand a little open book. He set his right foot on the sea, and his left on the land.'),
  ('Revelation', 10, 3, 'He cried with a loud voice, as a lion roars. When he cried, the seven thunders uttered their voices.'),
  ('Revelation', 10, 4, 'When the seven thunders sounded, I was about to write; but I heard a voice from the sky saying, “Seal up the things which the seven thunders said, and don’t write them.”'),
  ('Revelation', 10, 5, 'The angel whom I saw standing on the sea and on the land lifted up his right hand to the sky'),
  ('Revelation', 10, 6, 'and swore by him who lives forever and ever, who created heaven and the things that are in it, the earth and the things that are in it, and the sea and the things that are in it, that there will no longer be delay,'),
  ('Revelation', 10, 7, 'but in the days of the voice of the seventh angel, when he is about to sound, then the mystery of God is finished, as he declared to his servants the prophets.'),
  ('Revelation', 10, 8, 'The voice which I heard from heaven, again speaking with me, said, “Go, take the book which is open in the hand of the angel who stands on the sea and on the land.”'),
  ('Revelation', 10, 9, 'I went to the angel, telling him to give me the little book. He said to me, “Take it and eat it. It will make your stomach bitter, but in your mouth it will be as sweet as honey.”'),
  ('Revelation', 10, 10, 'I took the little book out of the angel’s hand, and ate it. It was as sweet as honey in my mouth. When I had eaten it, my stomach was made bitter.'),
  ('Revelation', 10, 11, 'They told me, “You must prophesy again over many peoples, nations, languages, and kings.”'),
  ('Revelation', 11, 1, 'A reed like a rod was given to me. Someone said, “Rise and measure God’s temple, and the altar, and those who worship in it.'),
  ('Revelation', 11, 2, 'Leave out the court which is outside of the temple, and don’t measure it, for it has been given to the nations. They will tread the holy city under foot for forty-two months.'),
  ('Revelation', 11, 3, 'I will give power to my two witnesses, and they will prophesy one thousand two hundred sixty days, clothed in sackcloth.”'),
  ('Revelation', 11, 4, 'These are the two olive trees and the two lamp stands, standing before the Lord of the earth.'),
  ('Revelation', 11, 5, 'If anyone desires to harm them, fire proceeds out of their mouth and devours their enemies. If anyone desires to harm them, he must be killed in this way.'),
  ('Revelation', 11, 6, 'These have the power to shut up the sky, that it may not rain during the days of their prophecy. They have power over the waters, to turn them into blood, and to strike the earth with every plague, as often as they desire.'),
  ('Revelation', 11, 7, 'When they have finished their testimony, the beast that comes up out of the abyss will make war with them, and overcome them, and kill them.'),
  ('Revelation', 11, 8, 'Their dead bodies will be in the street of the great city, which spiritually is called Sodom and Egypt, where also their Lord was crucified.'),
  ('Revelation', 11, 9, 'From among the peoples, tribes, languages, and nations, people will look at their dead bodies for three and a half days, and will not allow their dead bodies to be laid in a tomb.'),
  ('Revelation', 11, 10, 'Those who dwell on the earth will rejoice over them, and they will be glad. They will give gifts to one another, because these two prophets tormented those who dwell on the earth.'),
  ('Revelation', 11, 11, 'After the three and a half days, the breath of life from God entered into them, and they stood on their feet. Great fear fell on those who saw them.'),
  ('Revelation', 11, 12, 'I heard a loud voice from heaven saying to them, “Come up here!” They went up into heaven in a cloud, and their enemies saw them.'),
  ('Revelation', 11, 13, 'In that day there was a great earthquake, and a tenth of the city fell. Seven thousand people were killed in the earthquake, and the rest were terrified and gave glory to the God of heaven.'),
  ('Revelation', 11, 14, 'The second woe is past. Behold, the third woe comes quickly.'),
  ('Revelation', 11, 15, 'The seventh angel sounded, and great voices in heaven followed, saying, “The kingdom of the world has become the Kingdom of our Lord and of his Christ. He will reign forever and ever!”'),
  ('Revelation', 11, 16, 'The twenty-four elders, who sit on their thrones before God’s throne, fell on their faces and worshiped God,'),
  ('Revelation', 11, 17, 'saying: “We give you thanks, Lord God, the Almighty, the one who is and who was, because you have taken your great power and reigned.'),
  ('Revelation', 11, 18, 'The nations were angry, and your wrath came, as did the time for the dead to be judged, and to give your bondservants the prophets, their reward, as well as to the saints and those who fear your name, to the small and the great, and to destroy those who destroy the earth.”'),
  ('Revelation', 11, 19, 'God’s temple that is in heaven was opened, and the ark of the Lord’s covenant was seen in his temple. Lightnings, sounds, thunders, an earthquake, and great hail followed.'),
  ('Revelation', 12, 1, 'A great sign was seen in heaven: a woman clothed with the sun, and the moon under her feet, and on her head a crown of twelve stars.'),
  ('Revelation', 12, 2, 'She was with child. She cried out in pain, laboring to give birth.'),
  ('Revelation', 12, 3, 'Another sign was seen in heaven. Behold, a great red dragon, having seven heads and ten horns, and on his heads seven crowns.'),
  ('Revelation', 12, 4, 'His tail drew one third of the stars of the sky, and threw them to the earth. The dragon stood before the woman who was about to give birth, so that when she gave birth he might devour her child.'),
  ('Revelation', 12, 5, 'She gave birth to a son, a male child, who is to rule all the nations with a rod of iron. Her child was caught up to God and to his throne.'),
  ('Revelation', 12, 6, 'The woman fled into the wilderness, where she has a place prepared by God, that there they may nourish her one thousand two hundred sixty days.'),
  ('Revelation', 12, 7, 'There was war in the sky. Michael and his angels made war on the dragon. The dragon and his angels made war.'),
  ('Revelation', 12, 8, 'They didn’t prevail. No place was found for them any more in heaven.'),
  ('Revelation', 12, 9, 'The great dragon was thrown down, the old serpent, he who is called the devil and Satan, the deceiver of the whole world. He was thrown down to the earth, and his angels were thrown down with him.'),
  ('Revelation', 12, 10, 'I heard a loud voice in heaven, saying, “Now the salvation, the power, and the Kingdom of our God, and the authority of his Christ has come; for the accuser of our brothers has been thrown down, who accuses them before our God day and night.'),
  ('Revelation', 12, 11, 'They overcame him because of the Lamb’s blood, and because of the word of their testimony. They didn’t love their life, even to death.'),
  ('Revelation', 12, 12, 'Therefore rejoice, heavens, and you who dwell in them. Woe to the earth and to the sea, because the devil has gone down to you, having great wrath, knowing that he has but a short time.”');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Revelation', 12, 13, 'When the dragon saw that he was thrown down to the earth, he persecuted the woman who gave birth to the male child.'),
  ('Revelation', 12, 14, 'Two wings of the great eagle were given to the woman, that she might fly into the wilderness to her place, so that she might be nourished for a time, times, and half a time, from the face of the serpent.'),
  ('Revelation', 12, 15, 'The serpent spewed water out of his mouth after the woman like a river, that he might cause her to be carried away by the stream.'),
  ('Revelation', 12, 16, 'The earth helped the woman, and the earth opened its mouth and swallowed up the river which the dragon spewed out of his mouth.'),
  ('Revelation', 12, 17, 'The dragon grew angry with the woman, and went away to make war with the rest of her offspring, who keep God’s commandments and hold Jesus’ testimony.'),
  ('Revelation', 13, 1, 'Then I stood on the sand of the sea. I saw a beast coming up out of the sea, having ten horns and seven heads. On his horns were ten crowns, and on his heads, blasphemous names.'),
  ('Revelation', 13, 2, 'The beast which I saw was like a leopard, and his feet were like those of a bear, and his mouth like the mouth of a lion. The dragon gave him his power, his throne, and great authority.'),
  ('Revelation', 13, 3, 'One of his heads looked like it had been wounded fatally. His fatal wound was healed, and the whole earth marveled at the beast.'),
  ('Revelation', 13, 4, 'They worshiped the dragon because he gave his authority to the beast; and they worshiped the beast, saying, “Who is like the beast? Who is able to make war with him?”'),
  ('Revelation', 13, 5, 'A mouth speaking great things and blasphemy was given to him. Authority to make war for forty-two months was given to him.'),
  ('Revelation', 13, 6, 'He opened his mouth for blasphemy against God, to blaspheme his name, his dwelling, and those who dwell in heaven.'),
  ('Revelation', 13, 7, 'It was given to him to make war with the saints and to overcome them. Authority over every tribe, people, language, and nation was given to him.'),
  ('Revelation', 13, 8, 'All who dwell on the earth will worship him, everyone whose name has not been written from the foundation of the world in the book of life of the Lamb who has been killed.'),
  ('Revelation', 13, 9, 'If anyone has an ear, let him hear.'),
  ('Revelation', 13, 10, 'If anyone is to go into captivity, he will go into captivity. If anyone is to be killed with the sword, he must be killed. Here is the endurance and the faith of the saints.'),
  ('Revelation', 13, 11, 'I saw another beast coming up out of the earth. He had two horns like a lamb and it spoke like a dragon.'),
  ('Revelation', 13, 12, 'He exercises all the authority of the first beast in his presence. He makes the earth and those who dwell in it to worship the first beast, whose fatal wound was healed.'),
  ('Revelation', 13, 13, 'He performs great signs, even making fire come down out of the sky to the earth in the sight of people.'),
  ('Revelation', 13, 14, 'He deceives my own people who dwell on the earth because of the signs he was granted to do in front of the beast, saying to those who dwell on the earth that they should make an image to the beast who had the sword wound and lived.'),
  ('Revelation', 13, 15, 'It was given to him to give breath to the image of the beast, that the image of the beast should both speak, and cause as many as wouldn’t worship the image of the beast to be killed.'),
  ('Revelation', 13, 16, 'He causes all, the small and the great, the rich and the poor, and the free and the slave, to be given marks on their right hands or on their foreheads;'),
  ('Revelation', 13, 17, 'and that no one would be able to buy or to sell unless he has that mark, which is the name of the beast or the number of his name.'),
  ('Revelation', 13, 18, 'Here is wisdom. He who has understanding, let him calculate the number of the beast, for it is the number of a man. His number is six hundred sixty-six.'),
  ('Revelation', 14, 1, 'I saw, and behold, the Lamb standing on Mount Zion, and with him a number, one hundred forty-four thousand, having his name and the name of his Father written on their foreheads.'),
  ('Revelation', 14, 2, 'I heard a sound from heaven like the sound of many waters and like the sound of a great thunder. The sound which I heard was like that of harpists playing on their harps.'),
  ('Revelation', 14, 3, 'They sing a new song before the throne and before the four living creatures and the elders. No one could learn the song except the one hundred forty-four thousand, those who had been redeemed out of the earth.'),
  ('Revelation', 14, 4, 'These are those who were not defiled with women, for they are virgins. These are those who follow the Lamb wherever he goes. These were redeemed by Jesus from among men, the first fruits to God and to the Lamb.'),
  ('Revelation', 14, 5, 'In their mouth was found no lie, for they are blameless.'),
  ('Revelation', 14, 6, 'I saw an angel flying in mid heaven, having an eternal Good News to proclaim to those who dwell on the earth—to every nation, tribe, language, and people.'),
  ('Revelation', 14, 7, 'He said with a loud voice, “Fear the Lord, and give him glory, for the hour of his judgment has come. Worship him who made the heaven, the earth, the sea, and the springs of waters!”'),
  ('Revelation', 14, 8, 'Another, a second angel, followed, saying, “Babylon the great has fallen, which has made all the nations to drink of the wine of the wrath of her sexual immorality.”'),
  ('Revelation', 14, 9, 'Another angel, a third, followed them, saying with a great voice, “If anyone worships the beast and his image, and receives a mark on his forehead or on his hand,'),
  ('Revelation', 14, 10, 'he also will drink of the wine of the wrath of God, which is prepared unmixed in the cup of his anger. He will be tormented with fire and sulfur in the presence of the holy angels and in the presence of the Lamb.'),
  ('Revelation', 14, 11, 'The smoke of their torment goes up forever and ever. They have no rest day and night, those who worship the beast and his image, and whoever receives the mark of his name.'),
  ('Revelation', 14, 12, 'Here is the perseverance of the saints, those who keep the commandments of God and the faith of Jesus.”'),
  ('Revelation', 14, 13, 'I heard a voice from heaven saying, “Write, ‘Blessed are the dead who die in the Lord from now on.’” “Yes,” says the Spirit, “that they may rest from their labors, for their works follow with them.”'),
  ('Revelation', 14, 14, 'I looked, and saw a white cloud, and on the cloud one sitting like a son of man, having on his head a golden crown, and in his hand a sharp sickle.'),
  ('Revelation', 14, 15, 'Another angel came out of the temple, crying with a loud voice to him who sat on the cloud, “Send your sickle and reap, for the hour to reap has come; for the harvest of the earth is ripe!”'),
  ('Revelation', 14, 16, 'He who sat on the cloud thrust his sickle on the earth, and the earth was reaped.'),
  ('Revelation', 14, 17, 'Another angel came out of the temple which is in heaven. He also had a sharp sickle.'),
  ('Revelation', 14, 18, 'Another angel came out from the altar, he who has power over fire, and he called with a great voice to him who had the sharp sickle, saying, “Send your sharp sickle and gather the clusters of the vine of the earth, for the earth’s grapes are fully ripe!”'),
  ('Revelation', 14, 19, 'The angel thrust his sickle into the earth, and gathered the vintage of the earth and threw it into the great wine press of the wrath of God.'),
  ('Revelation', 14, 20, 'The wine press was trodden outside of the city, and blood came out of the wine press, up to the bridles of the horses, as far as one thousand six hundred stadia.'),
  ('Revelation', 15, 1, 'I saw another great and marvelous sign in the sky: seven angels having the seven last plagues, for in them God’s wrath is finished.'),
  ('Revelation', 15, 2, 'I saw something like a sea of glass mixed with fire, and those who overcame the beast, his image, and the number of his name, standing on the sea of glass, having harps of God.'),
  ('Revelation', 15, 3, 'They sang the song of Moses, the servant of God, and the song of the Lamb, saying, “Great and marvelous are your works, Lord God, the Almighty! Righteous and true are your ways, you King of the nations.'),
  ('Revelation', 15, 4, 'Who wouldn’t fear you, Lord, and glorify your name? For you only are holy. For all the nations will come and worship before you. For your righteous acts have been revealed.”'),
  ('Revelation', 15, 5, 'After these things I looked, and the temple of the tabernacle of the testimony in heaven was opened.'),
  ('Revelation', 15, 6, 'The seven angels who had the seven plagues came out, clothed with pure, bright linen, and wearing golden sashes around their chests.'),
  ('Revelation', 15, 7, 'One of the four living creatures gave to the seven angels seven golden bowls full of the wrath of God, who lives forever and ever.'),
  ('Revelation', 15, 8, 'The temple was filled with smoke from the glory of God and from his power. No one was able to enter into the temple until the seven plagues of the seven angels would be finished.'),
  ('Revelation', 16, 1, 'I heard a loud voice out of the temple, saying to the seven angels, “Go and pour out the seven bowls of the wrath of God on the earth!”'),
  ('Revelation', 16, 2, 'The first went, and poured out his bowl into the earth, and it became a harmful and painful sore on the people who had the mark of the beast, and who worshiped his image.'),
  ('Revelation', 16, 3, 'The second angel poured out his bowl into the sea, and it became blood as of a dead man. Every living thing in the sea died.'),
  ('Revelation', 16, 4, 'The third poured out his bowl into the rivers and springs of water, and they became blood.'),
  ('Revelation', 16, 5, 'I heard the angel of the waters saying, “You are righteous, who are and who were, O Holy One, because you have judged these things.'),
  ('Revelation', 16, 6, 'For they poured out the blood of saints and prophets, and you have given them blood to drink. They deserve this.”'),
  ('Revelation', 16, 7, 'I heard the altar saying, “Yes, Lord God, the Almighty, true and righteous are your judgments.”'),
  ('Revelation', 16, 8, 'The fourth poured out his bowl on the sun, and it was given to him to scorch men with fire.'),
  ('Revelation', 16, 9, 'People were scorched with great heat, and people blasphemed the name of God who has the power over these plagues. They didn’t repent and give him glory.'),
  ('Revelation', 16, 10, 'The fifth poured out his bowl on the throne of the beast, and his kingdom was darkened. They gnawed their tongues because of the pain,'),
  ('Revelation', 16, 11, 'and they blasphemed the God of heaven because of their pains and their sores. They still didn’t repent of their works.'),
  ('Revelation', 16, 12, 'The sixth poured out his bowl on the great river, the Euphrates. Its water was dried up, that the way might be prepared for the kings that come from the sunrise.'),
  ('Revelation', 16, 13, 'I saw coming out of the mouth of the dragon, and out of the mouth of the beast, and out of the mouth of the false prophet, three unclean spirits, something like frogs;'),
  ('Revelation', 16, 14, 'for they are spirits of demons, performing signs, which go out to the kings of the whole inhabited earth, to gather them together for the war of that great day of God the Almighty.'),
  ('Revelation', 16, 15, '“Behold, I come like a thief. Blessed is he who watches, and keeps his clothes, so that he doesn’t walk naked, and they see his shame.”'),
  ('Revelation', 16, 16, 'He gathered them together into the place which is called in Hebrew, “Harmagedon”.'),
  ('Revelation', 16, 17, 'The seventh poured out his bowl into the air. A loud voice came out of the temple of heaven, from the throne, saying, “It is done!”'),
  ('Revelation', 16, 18, 'There were lightnings, sounds, and thunders; and there was a great earthquake such as has not happened since there were men on the earth—so great an earthquake and so mighty.'),
  ('Revelation', 16, 19, 'The great city was divided into three parts, and the cities of the nations fell. Babylon the great was remembered in the sight of God, to give to her the cup of the wine of the fierceness of his wrath.'),
  ('Revelation', 16, 20, 'Every island fled away, and the mountains were not found.'),
  ('Revelation', 16, 21, 'Great hailstones, about the weight of a talent, came down out of the sky on people. People blasphemed God because of the plague of the hail, for this plague was exceedingly severe.'),
  ('Revelation', 17, 1, 'One of the seven angels who had the seven bowls came and spoke with me, saying, “Come here. I will show you the judgment of the great prostitute who sits on many waters,'),
  ('Revelation', 17, 2, 'with whom the kings of the earth committed sexual immorality. Those who dwell in the earth were made drunken with the wine of her sexual immorality.”'),
  ('Revelation', 17, 3, 'He carried me away in the Spirit into a wilderness. I saw a woman sitting on a scarlet-colored beast, full of blasphemous names, having seven heads and ten horns.'),
  ('Revelation', 17, 4, 'The woman was dressed in purple and scarlet, and decked with gold and precious stones and pearls, having in her hand a golden cup full of abominations and the impurities of the sexual immorality of the earth.'),
  ('Revelation', 17, 5, 'And on her forehead a name was written, “MYSTERY, BABYLON THE GREAT, THE MOTHER OF THE PROSTITUTES AND OF THE ABOMINATIONS OF THE EARTH.”'),
  ('Revelation', 17, 6, 'I saw the woman drunken with the blood of the saints and with the blood of the martyrs of Jesus. When I saw her, I wondered with great amazement.'),
  ('Revelation', 17, 7, 'The angel said to me, “Why do you wonder? I will tell you the mystery of the woman and of the beast that carries her, which has the seven heads and the ten horns.'),
  ('Revelation', 17, 8, 'The beast that you saw was, and is not; and is about to come up out of the abyss and to go into destruction. Those who dwell on the earth and whose names have not been written in the book of life from the foundation of the world will marvel when they see that the beast was, and is not, and shall be present.'),
  ('Revelation', 17, 9, 'Here is the mind that has wisdom. The seven heads are seven mountains on which the woman sits.'),
  ('Revelation', 17, 10, 'They are seven kings. Five have fallen, the one is, and the other has not yet come. When he comes, he must continue a little while.'),
  ('Revelation', 17, 11, 'The beast that was, and is not, is himself also an eighth, and is of the seven; and he goes to destruction.'),
  ('Revelation', 17, 12, 'The ten horns that you saw are ten kings who have received no kingdom as yet, but they receive authority as kings with the beast for one hour.'),
  ('Revelation', 17, 13, 'These have one mind, and they give their power and authority to the beast.'),
  ('Revelation', 17, 14, 'These will war against the Lamb, and the Lamb will overcome them, for he is Lord of lords and King of kings; and those who are with him are called, chosen, and faithful.”'),
  ('Revelation', 17, 15, 'He said to me, “The waters which you saw, where the prostitute sits, are peoples, multitudes, nations, and languages.'),
  ('Revelation', 17, 16, 'The ten horns which you saw, they and the beast will hate the prostitute, will make her desolate, will strip her naked, will eat her flesh, and will burn her utterly with fire.'),
  ('Revelation', 17, 17, 'For God has put in their hearts to do what he has in mind, to be of one mind, and to give their kingdom to the beast, until the words of God should be accomplished.'),
  ('Revelation', 17, 18, 'The woman whom you saw is the great city which reigns over the kings of the earth.”'),
  ('Revelation', 18, 1, 'After these things, I saw another angel coming down out of the sky, having great authority. The earth was illuminated with his glory.'),
  ('Revelation', 18, 2, 'He cried with a mighty voice, saying, “Fallen, fallen is Babylon the great, and she has become a habitation of demons, a prison of every unclean spirit, and a prison of every unclean and hated bird!'),
  ('Revelation', 18, 3, 'For all the nations have drunk of the wine of the wrath of her sexual immorality, the kings of the earth committed sexual immorality with her, and the merchants of the earth grew rich from the abundance of her luxury.”'),
  ('Revelation', 18, 4, 'I heard another voice from heaven, saying, “Come out of her, my people, that you have no participation in her sins, and that you don’t receive of her plagues,'),
  ('Revelation', 18, 5, 'for her sins have reached to the sky, and God has remembered her iniquities.'),
  ('Revelation', 18, 6, 'Return to her just as she returned, and repay her double as she did, and according to her works. In the cup which she mixed, mix to her double.'),
  ('Revelation', 18, 7, 'However much she glorified herself and grew wanton, so much give her of torment and mourning. For she says in her heart, ‘I sit a queen, and am no widow, and will in no way see mourning.’'),
  ('Revelation', 18, 8, 'Therefore in one day her plagues will come: death, mourning, and famine; and she will be utterly burned with fire, for the Lord God who has judged her is strong.'),
  ('Revelation', 18, 9, 'The kings of the earth who committed sexual immorality and lived wantonly with her will weep and wail over her, when they look at the smoke of her burning,'),
  ('Revelation', 18, 10, 'standing far away for the fear of her torment, saying, ‘Woe, woe, the great city, Babylon, the strong city! For your judgment has come in one hour.’');
INSERT INTO bible_verses (book_name, chapter, verse, text) VALUES
  ('Revelation', 18, 11, 'The merchants of the earth weep and mourn over her, for no one buys their merchandise any more:'),
  ('Revelation', 18, 12, 'merchandise of gold, silver, precious stones, pearls, fine linen, purple, silk, scarlet, all expensive wood, every vessel of ivory, every vessel made of most precious wood, and of brass, and iron, and marble;'),
  ('Revelation', 18, 13, 'and cinnamon, incense, perfume, frankincense, wine, olive oil, fine flour, wheat, cattle, sheep, horses, chariots, and people’s bodies and souls.'),
  ('Revelation', 18, 14, 'The fruits which your soul lusted after have been lost to you. All things that were dainty and sumptuous have perished from you, and you will find them no more at all.'),
  ('Revelation', 18, 15, 'The merchants of these things, who were made rich by her, will stand far away for the fear of her torment, weeping and mourning,'),
  ('Revelation', 18, 16, 'saying, ‘Woe, woe, the great city, she who was dressed in fine linen, purple, and scarlet, and decked with gold and precious stones and pearls!'),
  ('Revelation', 18, 17, 'For in an hour such great riches are made desolate.’ Every ship master, and everyone who sails anywhere, and mariners, and as many as gain their living by sea, stood far away,'),
  ('Revelation', 18, 18, 'and cried out as they looked at the smoke of her burning, saying, ‘What is like the great city?’'),
  ('Revelation', 18, 19, 'They cast dust on their heads, and cried, weeping and mourning, saying, ‘Woe, woe, the great city, in which all who had their ships in the sea were made rich by reason of her great wealth!’ For she is made desolate in one hour.'),
  ('Revelation', 18, 20, '“Rejoice over her, O heaven, you saints, apostles, and prophets, for God has judged your judgment on her.”'),
  ('Revelation', 18, 21, 'A mighty angel took up a stone like a great millstone and cast it into the sea, saying, “Thus with violence will Babylon, the great city, be thrown down, and will be found no more at all.'),
  ('Revelation', 18, 22, 'The voice of harpists, minstrels, flute players, and trumpeters will be heard no more at all in you. No craftsman of whatever craft will be found any more at all in you. The sound of a mill will be heard no more at all in you.'),
  ('Revelation', 18, 23, 'The light of a lamp will shine no more at all in you. The voice of the bridegroom and of the bride will be heard no more at all in you, for your merchants were the princes of the earth; for with your sorcery all the nations were deceived.'),
  ('Revelation', 18, 24, 'In her was found the blood of prophets and of saints, and of all who have been slain on the earth.”'),
  ('Revelation', 19, 1, 'After these things I heard something like a loud voice of a great multitude in heaven, saying, “Hallelujah! Salvation, power, and glory belong to our God;'),
  ('Revelation', 19, 2, 'for his judgments are true and righteous. For he has judged the great prostitute who corrupted the earth with her sexual immorality, and he has avenged the blood of his servants at her hand.”'),
  ('Revelation', 19, 3, 'A second said, “Hallelujah! Her smoke goes up forever and ever.”'),
  ('Revelation', 19, 4, 'The twenty-four elders and the four living creatures fell down and worshiped God who sits on the throne, saying, “Amen! Hallelujah!”'),
  ('Revelation', 19, 5, 'A voice came from the throne, saying, “Give praise to our God, all you his servants, you who fear him, the small and the great!”'),
  ('Revelation', 19, 6, 'I heard something like the voice of a great multitude, and like the voice of many waters, and like the voice of mighty thunders, saying, “Hallelujah! For the Lord our God, the Almighty, reigns!'),
  ('Revelation', 19, 7, 'Let’s rejoice and be exceedingly glad, and let’s give the glory to him. For the wedding of the Lamb has come, and his wife has made herself ready.”'),
  ('Revelation', 19, 8, 'It was given to her that she would array herself in bright, pure, fine linen, for the fine linen is the righteous acts of the saints.'),
  ('Revelation', 19, 9, 'He said to me, “Write, ‘Blessed are those who are invited to the wedding supper of the Lamb.’” He said to me, “These are true words of God.”'),
  ('Revelation', 19, 10, 'I fell down before his feet to worship him. He said to me, “Look! Don’t do it! I am a fellow bondservant with you and with your brothers who hold the testimony of Jesus. Worship God, for the testimony of Jesus is the Spirit of Prophecy.”'),
  ('Revelation', 19, 11, 'I saw heaven opened, and behold, a white horse, and he who sat on it is called Faithful and True. In righteousness he judges and makes war.'),
  ('Revelation', 19, 12, 'His eyes are a flame of fire, and on his head are many crowns. He has names written and a name written which no one knows but he himself.'),
  ('Revelation', 19, 13, 'He is clothed in a garment sprinkled with blood. His name is called “The Word of God.”'),
  ('Revelation', 19, 14, 'The armies which are in heaven, clothed in white, pure, fine linen, followed him on white horses.'),
  ('Revelation', 19, 15, 'Out of his mouth proceeds a sharp, double-edged sword that with it he should strike the nations. He will rule them with an iron rod. He treads the wine press of the fierceness of the wrath of God, the Almighty.'),
  ('Revelation', 19, 16, 'He has on his garment and on his thigh a name written, “KING OF KINGS AND LORD OF LORDS.”'),
  ('Revelation', 19, 17, 'I saw an angel standing in the sun. He cried with a loud voice, saying to all the birds that fly in the sky, “Come! Be gathered together to the great supper of God,'),
  ('Revelation', 19, 18, 'that you may eat the flesh of kings, the flesh of captains, the flesh of mighty men, and the flesh of horses and of those who sit on them, and the flesh of all men, both free and slave, small and great.”'),
  ('Revelation', 19, 19, 'I saw the beast, the kings of the earth, and their armies, gathered together to make war against him who sat on the horse and against his army.'),
  ('Revelation', 19, 20, 'The beast was taken, and with him the false prophet who worked the signs in his sight, with which he deceived those who had received the mark of the beast and those who worshiped his image. These two were thrown alive into the lake of fire that burns with sulfur.'),
  ('Revelation', 19, 21, 'The rest were killed with the sword of him who sat on the horse, the sword which came out of his mouth. So all the birds were filled with their flesh.'),
  ('Revelation', 20, 1, 'I saw an angel coming down out of heaven, having the key of the abyss and a great chain in his hand.'),
  ('Revelation', 20, 2, 'He seized the dragon, the old serpent, who is the devil and Satan, who deceives the whole inhabited earth, and bound him for a thousand years,'),
  ('Revelation', 20, 3, 'and cast him into the abyss, and shut it and sealed it over him, that he should deceive the nations no more until the thousand years were finished. After this, he must be freed for a short time.'),
  ('Revelation', 20, 4, 'I saw thrones, and they sat on them, and judgment was given to them. I saw the souls of those who had been beheaded for the testimony of Jesus and for the word of God, and such as didn’t worship the beast nor his image, and didn’t receive the mark on their forehead and on their hand. They lived and reigned with Christ for a thousand years.'),
  ('Revelation', 20, 5, 'The rest of the dead didn’t live until the thousand years were finished. This is the first resurrection.'),
  ('Revelation', 20, 6, 'Blessed and holy is he who has part in the first resurrection. Over these, the second death has no power, but they will be priests of God and of Christ, and will reign with him one thousand years.'),
  ('Revelation', 20, 7, 'And after the thousand years, Satan will be released from his prison'),
  ('Revelation', 20, 8, 'and he will come out to deceive the nations which are in the four corners of the earth, Gog and Magog, to gather them together to the war, whose number is as the sand of the sea.'),
  ('Revelation', 20, 9, 'They went up over the width of the earth and surrounded the camp of the saints and the beloved city. Fire came down out of heaven from God and devoured them.'),
  ('Revelation', 20, 10, 'The devil who deceived them was thrown into the lake of fire and sulfur, where the beast and the false prophet are also. They will be tormented day and night forever and ever.'),
  ('Revelation', 20, 11, 'I saw a great white throne and him who sat on it, from whose face the earth and the sky fled away. There was found no place for them.'),
  ('Revelation', 20, 12, 'I saw the dead, the great and the small, standing before the throne, and they opened books. Another book was opened, which is the book of life. The dead were judged out of the things which were written in the books, according to their works.'),
  ('Revelation', 20, 13, 'The sea gave up the dead who were in it. Death and Hades gave up the dead who were in them. They were judged, each one according to his works.'),
  ('Revelation', 20, 14, 'Death and Hades were thrown into the lake of fire. This is the second death, the lake of fire.'),
  ('Revelation', 20, 15, 'If anyone was not found written in the book of life, he was cast into the lake of fire.'),
  ('Revelation', 21, 1, 'I saw a new heaven and a new earth, for the first heaven and the first earth have passed away, and the sea is no more.'),
  ('Revelation', 21, 2, 'I saw the holy city, New Jerusalem, coming down out of heaven from God, prepared like a bride adorned for her husband.'),
  ('Revelation', 21, 3, 'I heard a loud voice out of heaven saying, “Behold, God’s dwelling is with people; and he will dwell with them, and they will be his people, and God himself will be with them as their God.'),
  ('Revelation', 21, 4, 'He will wipe away every tear from their eyes. Death will be no more; neither will there be mourning, nor crying, nor pain any more. The first things have passed away.”'),
  ('Revelation', 21, 5, 'He who sits on the throne said, “Behold, I am making all things new.” He said, “Write, for these words of God are faithful and true.”'),
  ('Revelation', 21, 6, 'He said to me, “I am the Alpha and the Omega, the Beginning and the End. I will give freely to him who is thirsty from the spring of the water of life.'),
  ('Revelation', 21, 7, 'He who overcomes, I will give him these things. I will be his God, and he will be my son.'),
  ('Revelation', 21, 8, 'But for the cowardly, unbelieving, sinners, abominable, murderers, sexually immoral, sorcerers, idolaters, and all liars, their part is in the lake that burns with fire and sulfur, which is the second death.”'),
  ('Revelation', 21, 9, 'One of the seven angels who had the seven bowls which were loaded with the seven last plagues came, and he spoke with me, saying, “Come here. I will show you the bride, the Lamb’s wife.”'),
  ('Revelation', 21, 10, 'He carried me away in the Spirit to a great and high mountain, and showed me the holy city, Jerusalem, coming down out of heaven from God,'),
  ('Revelation', 21, 11, 'having the glory of God. Her light was like a most precious stone, like a jasper stone, clear as crystal;'),
  ('Revelation', 21, 12, 'having a great and high wall with twelve gates, and at the gates twelve angels, and names written on them, which are the names of the twelve tribes of the children of Israel.'),
  ('Revelation', 21, 13, 'On the east were three gates, and on the north three gates, and on the south three gates, and on the west three gates.'),
  ('Revelation', 21, 14, 'The wall of the city had twelve foundations, and on them twelve names of the twelve Apostles of the Lamb.'),
  ('Revelation', 21, 15, 'He who spoke with me had for a measure a golden reed to measure the city, its gates, and its walls.'),
  ('Revelation', 21, 16, 'The city is square. Its length is as great as its width. He measured the city with the reed: twelve thousand twelve stadia. Its length, width, and height are equal.'),
  ('Revelation', 21, 17, 'Its wall is one hundred forty-four cubits, by the measure of a man, that is, of an angel.'),
  ('Revelation', 21, 18, 'The construction of its wall was jasper. The city was pure gold, like pure glass.'),
  ('Revelation', 21, 19, 'The foundations of the city’s wall were adorned with all kinds of precious stones. The first foundation was jasper, the second sapphire, the third chalcedony, the fourth emerald,'),
  ('Revelation', 21, 20, 'the fifth sardonyx, the sixth sardius, the seventh chrysolite, the eighth beryl, the ninth topaz, the tenth chrysoprase, the eleventh jacinth, and the twelfth amethyst.'),
  ('Revelation', 21, 21, 'The twelve gates were twelve pearls. Each one of the gates was made of one pearl. The street of the city was pure gold, like transparent glass.'),
  ('Revelation', 21, 22, 'I saw no temple in it, for the Lord God the Almighty and the Lamb are its temple.'),
  ('Revelation', 21, 23, 'The city has no need for the sun or moon to shine, for the very glory of God illuminated it and its lamp is the Lamb.'),
  ('Revelation', 21, 24, 'The nations will walk in its light. The kings of the earth bring the glory and honor of the nations into it.'),
  ('Revelation', 21, 25, 'Its gates will in no way be shut by day (for there will be no night there),'),
  ('Revelation', 21, 26, 'and they shall bring the glory and the honor of the nations into it so that they may enter.'),
  ('Revelation', 21, 27, 'There will in no way enter into it anything profane, or one who causes an abomination or a lie, but only those who are written in the Lamb’s book of life.'),
  ('Revelation', 22, 1, 'He showed me a river of water of life, clear as crystal, proceeding out of the throne of God and of the Lamb,'),
  ('Revelation', 22, 2, 'in the middle of its street. On this side of the river and on that was the tree of life, bearing twelve kinds of fruits, yielding its fruit every month. The leaves of the tree were for the healing of the nations.'),
  ('Revelation', 22, 3, 'There will be no curse any more. The throne of God and of the Lamb will be in it, and his servants will serve him.'),
  ('Revelation', 22, 4, 'They will see his face, and his name will be on their foreheads.'),
  ('Revelation', 22, 5, 'There will be no night, and they need no lamp light or sun light; for the Lord God will illuminate them. They will reign forever and ever.'),
  ('Revelation', 22, 6, 'He said to me, “These words are faithful and true. The Lord God of the spirits of the prophets sent his angel to show to his bondservants the things which must happen soon.”'),
  ('Revelation', 22, 7, '“Behold, I am coming soon! Blessed is he who keeps the words of the prophecy of this book.”'),
  ('Revelation', 22, 8, 'Now I, John, am the one who heard and saw these things. When I heard and saw, I fell down to worship before the feet of the angel who had shown me these things.'),
  ('Revelation', 22, 9, 'He said to me, “You must not do that! I am a fellow bondservant with you and with your brothers, the prophets, and with those who keep the words of this book. Worship God.”'),
  ('Revelation', 22, 10, 'He said to me, “Don’t seal up the words of the prophecy of this book, for the time is at hand.'),
  ('Revelation', 22, 11, 'He who acts unjustly, let him act unjustly still. He who is filthy, let him be filthy still. He who is righteous, let him do righteousness still. He who is holy, let him be holy still.”'),
  ('Revelation', 22, 12, '“Behold, I am coming soon! My reward is with me, to repay to each man according to his work.'),
  ('Revelation', 22, 13, 'I am the Alpha and the Omega, the First and the Last, the Beginning and the End.'),
  ('Revelation', 22, 14, 'Blessed are those who do his commandments, that they may have the right to the tree of life, and may enter in by the gates into the city.'),
  ('Revelation', 22, 15, 'Outside are the dogs, the sorcerers, the sexually immoral, the murderers, the idolaters, and everyone who loves and practices falsehood.'),
  ('Revelation', 22, 16, 'I, Jesus, have sent my angel to testify these things to you for the assemblies. I am the root and the offspring of David, the Bright and Morning Star.”'),
  ('Revelation', 22, 17, 'The Spirit and the bride say, “Come!” He who hears, let him say, “Come!” He who is thirsty, let him come. He who desires, let him take the water of life freely.'),
  ('Revelation', 22, 18, 'I testify to everyone who hears the words of the prophecy of this book: if anyone adds to them, God will add to him the plagues which are written in this book.'),
  ('Revelation', 22, 19, 'If anyone takes away from the words of the book of this prophecy, God will take away his part from the tree of life, and out of the holy city, which are written in this book.'),
  ('Revelation', 22, 20, 'He who testifies these things says, “Yes, I am coming soon.” Amen! Yes, come, Lord Jesus!'),
  ('Revelation', 22, 21, 'The grace of the Lord Jesus Christ be with all the saints. Amen.');
